/**
 * Convert a 0-based character offset in `content` to a 1-based line and column.
 */
export function offsetToLineCol(content: string, offset: number): { line: number; col: number } {
  let line = 1;
  let lineStart = 0;
  for (let i = 0; i < offset; i++) {
    if (content[i] === "\n") {
      line++;
      lineStart = i + 1;
    }
  }
  return { line, col: offset - lineStart + 1 };
}

/**
 * Convert a 1-based line and column to a 0-based character offset in `content`.
 * Throws `RangeError` when `line` exceeds the number of lines in the content.
 */
export function lineColToOffset(content: string, line: number, col: number): number {
  const lines = content.split("\n");
  if (line - 1 >= lines.length) {
    throw new RangeError(`Line ${line} out of range (file has ${lines.length} line(s))`);
  }
  let offset = 0;
  for (let i = 0; i < line - 1; i++) {
    offset += lines[i].length + 1; // +1 for \n
  }
  return offset + col - 1;
}

/**
 * Apply an array of non-overlapping text edits to a source string.
 * Edits are applied in descending offset order so earlier offsets stay valid.
 */
export function applyTextEdits(
  text: string,
  edits: readonly { span: { start: number; length: number }; newText: string }[],
): string {
  const sorted = [...edits].sort((a, b) => b.span.start - a.span.start);
  let result = text;
  for (const edit of sorted) {
    result =
      result.slice(0, edit.span.start) +
      edit.newText +
      result.slice(edit.span.start + edit.span.length);
  }
  return result;
}

src/daemon/dispatcher.ts.source:
import {
  DeleteFileArgsSchema,
  ExtractFunctionArgsSchema,
  FindImportersArgsSchema,
  FindReferencesArgsSchema,
  GetDefinitionArgsSchema,
  GetTypeErrorsArgsSchema,
  MoveArgsSchema,
  MoveDirectoryArgsSchema,
  MoveSymbolArgsSchema,
  RenameArgsSchema,
  ReplaceTextArgsSchema,
  SearchTextArgsSchema,
} from "../adapters/schema.js";
import { isWithinWorkspace, validateFilePath } from "../domain/security.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { extractFunction } from "../operations/extractFunction.js";
import { findImporters } from "../operations/findImporters.js";
import { findReferences } from "../operations/findReferences.js";
import { getDefinition } from "../operations/getDefinition.js";
import { getTypeErrors } from "../operations/getTypeErrors.js";
import { moveDirectory } from "../operations/moveDirectory.js";
import { moveFile } from "../operations/moveFile.js";
import { rename } from "../operations/rename.js";
import { replaceText } from "../operations/replaceText.js";
import { searchText } from "../operations/searchText.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import type { EngineRegistry } from "../ts-engine/types.js";
import { makeRegistry } from "./language-plugin-registry.js";
import { getTypeErrorsForFiles } from "./post-write-diagnostics.js";

export { createVueLanguagePlugin } from "../plugins/vue/plugin.js";
export type { LanguagePlugin } from "../ts-engine/types.js";
export {
  clearLanguagePlugins,
  invalidateAll,
  invalidateFile,
  makeRegistry,
  registerLanguagePlugin,
} from "./language-plugin-registry.js";

// ─── Operation descriptor table ───────────────────────────────────────────

interface OperationDescriptor {
  /** Param keys that hold file paths requiring workspace validation. */
  pathParams: string[];
  /** Zod schema used to validate incoming params at the socket boundary. */
  schema: {
    safeParse(
      data: unknown,
    ):
      | { success: true; data: Record<string, unknown> }
      | { success: false; error: { issues: Array<{ message: string }> } };
  };
  /** Call the appropriate compiler method and return the raw result. */
  invoke(
    registry: EngineRegistry,
    params: Record<string, unknown>,
    workspace: string,
  ): Promise<unknown>;
}

const OPERATIONS: Record<string, OperationDescriptor> = {
  rename: {
    pathParams: ["file"],
    schema: RenameArgsSchema,
    async invoke(registry, params, workspace) {
      const { file, line, col, newName } = params as {
        file: string;
        line: number;
        col: number;
        newName: string;
      };
      const engine = await registry.projectEngine();
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      return rename(engine, file, line, col, newName, scope);
    },
  },

  moveFile: {
    pathParams: ["oldPath", "newPath"],
    schema: MoveArgsSchema,
    async invoke(registry, params, workspace) {
      const { oldPath, newPath } = params as { oldPath: string; newPath: string };
      const engine = await registry.projectEngine();
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      return moveFile(engine, oldPath, newPath, scope);
    },
  },

  moveDirectory: {
    pathParams: ["oldPath", "newPath"],
    schema: MoveDirectoryArgsSchema,
    async invoke(registry, params, workspace) {
      const { oldPath, newPath } = params as { oldPath: string; newPath: string };
      const engine = await registry.projectEngine();
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      return moveDirectory(engine, oldPath, newPath, scope);
    },
  },

  moveSymbol: {
    pathParams: ["sourceFile", "destFile"],
    schema: MoveSymbolArgsSchema,
    async invoke(registry, params, workspace) {
      const { sourceFile, symbolName, destFile, force } = params as {
        sourceFile: string;
        symbolName: string;
        destFile: string;
        force?: boolean;
      };
      const engine = await registry.projectEngine();
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      const { moveSymbol } = await import("../operations/moveSymbol.js");
      return moveSymbol(engine, sourceFile, symbolName, destFile, scope, { force });
    },
  },

  extractFunction: {
    pathParams: ["file"],
    schema: ExtractFunctionArgsSchema,
    async invoke(registry, params, workspace) {
      const { file, startLine, startCol, endLine, endCol, functionName } = params as {
        file: string;
        startLine: number;
        startCol: number;
        endLine: number;
        endCol: number;
        functionName: string;
      };
      const engine = await registry.projectEngine();
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      return extractFunction(
        engine,
        file,
        startLine,
        startCol,
        endLine,
        endCol,
        functionName,
        scope,
      );
    },
  },

  findImporters: {
    pathParams: ["file"],
    schema: FindImportersArgsSchema,
    async invoke(registry, params) {
      const { file } = params as { file: string };
      const engine = await registry.projectEngine();
      return findImporters(engine, file);
    },
  },

  findReferences: {
    pathParams: ["file"],
    schema: FindReferencesArgsSchema,
    async invoke(registry, params) {
      const { file, line, col } = params as { file: string; line: number; col: number };
      const engine = await registry.projectEngine();
      return findReferences(engine, file, line, col);
    },
  },

  getDefinition: {
    pathParams: ["file"],
    schema: GetDefinitionArgsSchema,
    async invoke(registry, params) {
      const { file, line, col } = params as { file: string; line: number; col: number };
      const engine = await registry.projectEngine();
      return getDefinition(engine, file, line, col);
    },
  },

  getTypeErrors: {
    pathParams: [],
    schema: GetTypeErrorsArgsSchema,
    async invoke(registry, params, workspace) {
      const { file } = params as { file?: string };
      const tsEngine = await registry.tsEngine();
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      return getTypeErrors(tsEngine, file, scope);
    },
  },

  searchText: {
    pathParams: [],
    schema: SearchTextArgsSchema,
    async invoke(_registry, params, workspace) {
      const { pattern, glob, context, maxResults } = params as {
        pattern: string;
        glob?: string;
        context?: number;
        maxResults?: number;
      };
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      return searchText(pattern, scope, { glob, context, maxResults });
    },
  },

  deleteFile: {
    pathParams: ["file"],
    schema: DeleteFileArgsSchema,
    async invoke(registry, params, workspace) {
      const { file } = params as { file: string };
      const engine = await registry.projectEngine();
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      const { deleteFile } = await import("../operations/deleteFile.js");
      return deleteFile(engine, file, scope);
    },
  },

  replaceText: {
    pathParams: [],
    schema: ReplaceTextArgsSchema,
    async invoke(_registry, params, workspace) {
      const { pattern, replacement, glob, edits } = params as {
        pattern?: string;
        replacement?: string;
        glob?: string;
        edits?: Array<{
          file: string;
          line: number;
          col: number;
          oldText: string;
          newText: string;
        }>;
      };
      const scope = new WorkspaceScope(workspace, new NodeFileSystem());
      return replaceText(scope, { pattern, replacement, glob, edits });
    },
  },
};

// ─── Dispatcher ────────────────────────────────────────────────────────────

export async function dispatchRequest(
  req: { method: string; params: Record<string, unknown> },
  workspace: string,
): Promise<object> {
  const descriptor = OPERATIONS[req.method];
  if (!descriptor) {
    return {
      status: "error" as const,
      error: "UNKNOWN_METHOD",
      message: `Unknown method: ${req.method}`,
    };
  }

  const parsed = descriptor.schema.safeParse(req.params);
  if (!parsed.success) {
    const message = parsed.error.issues.map((i) => i.message).join("; ");
    return { status: "error" as const, error: "VALIDATION_ERROR", message };
  }

  for (const paramKey of descriptor.pathParams) {
    const value = req.params[paramKey] as string;
    const pathResult = validateFilePath(value);
    if (!pathResult.ok) {
      return {
        status: "error" as const,
        error: "INVALID_PATH",
        message:
          pathResult.reason === "CONTROL_CHARS"
            ? `path contains control characters: ${paramKey}`
            : `path contains URI fragment or query character: ${paramKey}`,
      };
    }
    if (!isWithinWorkspace(value, workspace)) {
      return {
        status: "error" as const,
        error: "WORKSPACE_VIOLATION",
        message: `${paramKey} is outside the workspace: ${value}`,
      };
    }
  }

  const registry =
    descriptor.pathParams.length > 0
      ? makeRegistry(req.params[descriptor.pathParams[0]] as string, workspace)
      : makeRegistry(workspace, workspace);

  const result = (await descriptor.invoke(registry, parsed.data, workspace)) as Record<
    string,
    unknown
  >;

  if (
    parsed.data.checkTypeErrors !== false &&
    Array.isArray(result.filesModified) &&
    (result.filesModified as string[]).length > 0
  ) {
    const tsEngine = await registry.tsEngine();
    const diagnostics = getTypeErrorsForFiles(
      tsEngine,
      result.filesModified as string[],
      new NodeFileSystem(),
    );
    result.typeErrors = diagnostics.typeErrors;
    result.typeErrorCount = diagnostics.typeErrorCount;
    result.typeErrorsTruncated = diagnostics.typeErrorsTruncated;
  }

  const status =
    typeof result.typeErrorCount === "number" && result.typeErrorCount > 0
      ? ("warn" as const)
      : ("success" as const);
  return { status, ...result };
}

src/ts-engine/remove-importers.ts.source:
import type {
  ExportDeclaration,
  ImportDeclaration,
  SourceFile as TsMorphSourceFile,
} from "ts-morph";
import type { WorkspaceScope } from "../domain/workspace-scope.js";
import type { TsMorphEngine } from "./engine.js";

/**
 * Removes all import and export declarations that reference `targetFile` from
 * every in-scope TS/JS file. In-project files are resolved via the ts-morph
 * compiler.
 *
 * Returns the total count of declarations removed across all files.
 *
 * Files outside `scope.root` are recorded as skipped and never written.
 */
export async function tsRemoveImportersOf(
  compiler: TsMorphEngine,
  targetFile: string,
  scope: WorkspaceScope,
): Promise<number> {
  return removeInProjectImporters(compiler, targetFile, scope);
}

/**
 * In-project TS/JS cleanup via ts-morph.
 * ts-morph resolves module specifiers through the compiler, so it correctly
 * handles path aliases, index files, and all extension variants.
 */
async function removeInProjectImporters(
  compiler: TsMorphEngine,
  targetFile: string,
  scope: WorkspaceScope,
): Promise<number> {
  const project = compiler.getProjectForFile(targetFile);
  if (!project.getSourceFile(targetFile)) {
    project.addSourceFileAtPath(targetFile);
  }

  let removed = 0;

  for (const sf of project.getSourceFiles()) {
    const filePath = sf.getFilePath() as string;
    if (filePath === targetFile) continue;

    const hasRefs =
      sf
        .getImportDeclarations()
        .some((d) => d.getModuleSpecifierSourceFile()?.getFilePath() === targetFile) ||
      sf
        .getExportDeclarations()
        .some((d) => d.getModuleSpecifierSourceFile()?.getFilePath() === targetFile);

    if (!hasRefs) continue;

    if (!scope.contains(filePath)) {
      scope.recordSkipped(filePath);
      continue;
    }

    removed += removeMatchingDeclarations(
      sf,
      (decl) => decl.getModuleSpecifierSourceFile()?.getFilePath() === targetFile,
    );

    scope.recordModified(filePath);
  }

  for (const sf of project.getSourceFiles()) {
    if (!sf.isSaved() && scope.contains(sf.getFilePath() as string)) {
      await sf.save();
    }
  }

  return removed;
}

/**
 * Remove import/export declarations from a source file one at a time,
 * re-querying after each removal so stale node references are never used.
 * Returns the count of declarations removed.
 */
function removeMatchingDeclarations(
  sf: TsMorphSourceFile,
  predicate: (decl: ImportDeclaration | ExportDeclaration) => boolean,
): number {
  let removed = 0;
  let found = true;
  while (found) {
    found = false;
    for (const decl of [...sf.getImportDeclarations(), ...sf.getExportDeclarations()]) {
      if (predicate(decl)) {
        decl.remove();
        removed++;
        found = true;
        break;
      }
    }
  }
  return removed;
}

