import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import { cleanup, copyFixture, FIXTURES } from "../__testHelpers__/helpers.js";
import { EngineError } from "../domain/errors.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { TsMorphEngine } from "./engine.js";

function makeScope(dir: string): WorkspaceScope {
  return new WorkspaceScope(dir, new NodeFileSystem());
}

// simple-ts fixture:
//   src/utils.ts  line 1, col 17 → greetUser
//   src/main.ts   line 1, col 10 → greetUser (import)
//                 line 3, col 13 → greetUser (call)

describe("TsMorphEngine", () => {
  const dirs: string[] = [];
  afterEach(() => dirs.splice(0).forEach(cleanup));

  function setup(fixture = FIXTURES.simpleTs.name) {
    const dir = copyFixture(fixture);
    dirs.push(dir);
    return dir;
  }

  it("implements Engine interface shape", () => {
    const p = new TsMorphEngine();
    expect(typeof p.resolveOffset).toBe("function");
    expect(typeof p.getReferencesAtPosition).toBe("function");
    expect(typeof p.getDefinitionAtPosition).toBe("function");
    expect(typeof p.readFile).toBe("function");
    expect(typeof p.rename).toBe("function");
    expect(typeof p.moveFile).toBe("function");
    expect(typeof p.moveSymbol).toBe("function");
    expect(typeof p.moveDirectory).toBe("function");
    expect(typeof p.deleteFile).toBe("function");
  });

  it("resolveOffset converts 1-based line/col to 0-based offset", () => {
    const dir = setup();
    const p = new TsMorphEngine();
    const file = path.join(dir, "src/utils.ts");
    // line 1, col 1 → offset 0
    expect(p.resolveOffset(file, 1, 1)).toBe(0);
    // line 1, col 17 → offset 16 (0-based)
    expect(p.resolveOffset(file, 1, 17)).toBe(16);
  });

  it("getRenameLocations returns spans for a symbol", async () => {
    const dir = setup();
    const p = new TsMorphEngine();
    const file = path.join(dir, "src/utils.ts");
    const offset = p.resolveOffset(file, 1, 17); // greetUser
    const locs = await p.getRenameLocations(file, offset);
    expect(locs).not.toBeNull();
    expect(locs?.length).toBeGreaterThanOrEqual(2); // declaration + call site + import
    for (const loc of locs ?? []) {
      expect(typeof loc.fileName).toBe("string");
      expect(typeof loc.textSpan.start).toBe("number");
      expect(typeof loc.textSpan.length).toBe("number");
    }
  });

  it("getReferencesAtPosition returns spans including definition", async () => {
    const dir = setup();
    const p = new TsMorphEngine();
    const file = path.join(dir, "src/utils.ts");
    const offset = p.resolveOffset(file, 1, 17);
    const refs = await p.getReferencesAtPosition(file, offset);
    expect(refs).not.toBeNull();
    expect(refs?.length).toBeGreaterThanOrEqual(1);
  });

  it("getDefinitionAtPosition returns definition location", async () => {
    const dir = setup();
    const p = new TsMorphEngine();
    const file = path.join(dir, "src/main.ts");
    const offset = p.resolveOffset(file, 3, 13); // greetUser call site
    const defs = await p.getDefinitionAtPosition(file, offset);
    expect(defs).not.toBeNull();
    expect(defs?.length).toBeGreaterThanOrEqual(1);
    expect(defs?.[0].name).toBe("greetUser");
    expect(defs?.[0].fileName).toContain("utils.ts");
  });

  it("refreshFile is a no-op when the project has not been loaded yet", () => {
    const p = new TsMorphEngine();
    expect(() => p.refreshFile("/nonexistent/path.ts")).not.toThrow();
  });

  it("refreshFile does not throw after a project has been loaded", () => {
    const dir = setup();
    const p = new TsMorphEngine();
    const file = path.join(dir, "src/utils.ts");
    // Force project load.
    p.resolveOffset(file, 1, 1);
    // Modify file on disk then refresh — must not throw.
    expect(() => p.refreshFile(file)).not.toThrow();
  });

  it("getRenameLocations throws RENAME_NOT_ALLOWED for a non-renameable token", async () => {
    const dir = setup();
    const p = new TsMorphEngine();
    // main.ts line 1: import { greetUser } from "./utils";
    // The import path string "./utils" at col 27 cannot be renamed
    // because allowRenameOfImportPath:false is passed to the TS LS.
    const file = path.join(dir, "src/main.ts");
    const offset = p.resolveOffset(file, 1, 27); // '"' of '"./utils"'
    await expect(p.getRenameLocations(file, offset)).rejects.toSatisfy((e) =>
      EngineError.is(e, "RENAME_NOT_ALLOWED"),
    );
  });

  it("getDefinitionAtPosition returns null for a whitespace offset", async () => {
    const dir = setup();
    const p = new TsMorphEngine();
    // main.ts line 2 is blank — any position there has no symbol definition
    const file = path.join(dir, "src/main.ts");
    const result = await p.getDefinitionAtPosition(file, 37); // '\n' at end of line 1
    expect(result).toBeNull();
  });

  it("resolveOffset works for a file with no parent tsconfig (no-tsconfig project path)", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-notconfig-"));
    const file = path.join(tmpDir, "standalone.ts");
    fs.writeFileSync(file, "export const x = 1;\n");
    try {
      const p = new TsMorphEngine();
      // 'x' starts at column 14 → offset 13
      expect(p.resolveOffset(file, 1, 14)).toBe(13);
    } finally {
      fs.rmSync(tmpDir, { recursive: true, force: true });
    }
  });

  it("getRenameLocations works for a file with no parent tsconfig", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-notconfig-"));
    const file = path.join(tmpDir, "standalone.ts");
    fs.writeFileSync(file, "export const myVar = 1;\n");
    try {
      const p = new TsMorphEngine();
      // 'myVar' starts at offset 13
      const locs = await p.getRenameLocations(file, 13);
      expect(locs).not.toBeNull();
      expect(locs?.length).toBeGreaterThanOrEqual(1);
    } finally {
      fs.rmSync(tmpDir, { recursive: true, force: true });
    }
  });

  it("getReferencesAtPosition works for a file with no parent tsconfig", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-notconfig-"));
    const file = path.join(tmpDir, "standalone.ts");
    fs.writeFileSync(file, "export const myVar = 1;\n");
    try {
      const p = new TsMorphEngine();
      const refs = await p.getReferencesAtPosition(file, 13);
      expect(refs).not.toBeNull();
    } finally {
      fs.rmSync(tmpDir, { recursive: true, force: true });
    }
  });

  it("getDefinitionAtPosition works for a file with no parent tsconfig", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-notconfig-"));
    const file = path.join(tmpDir, "standalone.ts");
    // Use a reference expression: x references myVar defined earlier in the file
    fs.writeFileSync(file, "export const myVar = 1;\nexport const x = myVar;\n");
    try {
      const p = new TsMorphEngine();
      // 'myVar' in 'const x = myVar' starts at offset 41
      const content = fs.readFileSync(file, "utf8");
      const offset = content.indexOf("myVar", content.indexOf("const x"));
      const defs = await p.getDefinitionAtPosition(file, offset);
      expect(defs).not.toBeNull();
    } finally {
      fs.rmSync(tmpDir, { recursive: true, force: true });
    }
  });

  describe("symlink path resolution", () => {
    function setupSymlink() {
      const realDir = copyFixture(FIXTURES.simpleTs.name);
      dirs.push(realDir);
      const linkDir = `${realDir}-link`;
      fs.symlinkSync(realDir, linkDir, "dir");
      dirs.push(linkDir);
      return { realDir, linkDir };
    }

    it("resolveOffset works through a symlinked path", () => {
      const { linkDir } = setupSymlink();
      const p = new TsMorphEngine();
      const file = path.join(linkDir, "src/utils.ts");
      expect(p.resolveOffset(file, 1, 17)).toBe(16);
    });

    it("getRenameLocations succeeds through a symlinked path", async () => {
      const { linkDir } = setupSymlink();
      const p = new TsMorphEngine();
      const file = path.join(linkDir, "src/utils.ts");
      const offset = p.resolveOffset(file, 1, 17);
      const locs = await p.getRenameLocations(file, offset);
      expect(locs).not.toBeNull();
      expect(locs?.length).toBeGreaterThanOrEqual(2);
      // Response paths should be real (usable) paths
      for (const loc of locs ?? []) {
        expect(fs.existsSync(loc.fileName)).toBe(true);
      }
    });

    it("getReferencesAtPosition succeeds through a symlinked path", async () => {
      const { linkDir } = setupSymlink();
      const p = new TsMorphEngine();
      const file = path.join(linkDir, "src/utils.ts");
      const offset = p.resolveOffset(file, 1, 17);
      const refs = await p.getReferencesAtPosition(file, offset);
      expect(refs).not.toBeNull();
      expect(refs?.length).toBeGreaterThanOrEqual(1);
      for (const ref of refs ?? []) {
        expect(fs.existsSync(ref.fileName)).toBe(true);
      }
    });

    it("getDefinitionAtPosition succeeds through a symlinked path", async () => {
      const { linkDir } = setupSymlink();
      const p = new TsMorphEngine();
      const file = path.join(linkDir, "src/main.ts");
      const offset = p.resolveOffset(file, 3, 13); // greetUser call site
      const defs = await p.getDefinitionAtPosition(file, offset);
      expect(defs).not.toBeNull();
      expect(defs?.length).toBeGreaterThanOrEqual(1);
      expect(defs?.[0].name).toBe("greetUser");
      for (const def of defs ?? []) {
        expect(fs.existsSync(def.fileName)).toBe(true);
      }
    });
  });

  it("getProjectForDirectory falls back to no-tsconfig project when no tsconfig found", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-notconfig-dir-"));
    try {
      const p = new TsMorphEngine();
      // Must not throw — returns a bare Project without tsconfig.
      const project = p.getProjectForDirectory(tmpDir);
      expect(project).toBeTruthy();
    } finally {
      fs.rmSync(tmpDir, { recursive: true, force: true });
    }
  });

  describe("getLanguageServiceForFile", () => {
    it("returns a language service with getSemanticDiagnostics", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const file = path.join(dir, "src/utils.ts");
      const ls = p.getLanguageServiceForFile(file);
      expect(typeof ls.getSemanticDiagnostics).toBe("function");
    });

    it("returns a language service that can find rename locations", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const file = path.join(dir, "src/utils.ts");
      const ls = p.getLanguageServiceForFile(file);
      // greetUser is at offset 16 in utils.ts
      const locs = ls.findRenameLocations(file, 16, false, false, {
        allowRenameOfImportPath: false,
      });
      expect(locs).not.toBeUndefined();
      expect(locs?.length).toBeGreaterThanOrEqual(2);
    });

    it("adds the file to the project when it was not already tracked", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const file = path.join(dir, "src/utils.ts");
      // Call before any other method — file is not yet in a project.
      const ls = p.getLanguageServiceForFile(file);
      const diags = ls.getSemanticDiagnostics(file);
      expect(Array.isArray(diags)).toBe(true);
    });
  });

  describe("getLanguageServiceForDirectory", () => {
    it("returns a language service for the project covering the directory", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const ls = p.getLanguageServiceForDirectory(dir);
      expect(typeof ls.getSemanticDiagnostics).toBe("function");
    });

    it("returns a language service that can check files in the project", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const ls = p.getLanguageServiceForDirectory(dir);
      const file = path.join(dir, "src/utils.ts");
      const diags = ls.getSemanticDiagnostics(file);
      expect(Array.isArray(diags)).toBe(true);
    });
  });

  describe("refreshSourceFile", () => {
    it("is a no-op when the project has not been loaded yet", () => {
      const p = new TsMorphEngine();
      expect(() => p.refreshSourceFile("/nonexistent/path.ts")).not.toThrow();
    });

    it("re-reads the file from disk after content changes", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const file = path.join(dir, "src/utils.ts");
      // Load the project so the file is tracked.
      p.getLanguageServiceForFile(file);
      // Overwrite the file with a type error.
      fs.writeFileSync(file, "export const x: number = 'not-a-number';\n");
      p.refreshSourceFile(file);
      const ls = p.getLanguageServiceForFile(file);
      const diags = ls.getSemanticDiagnostics(file);
      expect(diags.length).toBeGreaterThan(0);
    });

    it("adds the file to the project when it was not already tracked", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const file = path.join(dir, "src/utils.ts");
      // Load the project (but not this specific file).
      const otherFile = path.join(dir, "src/main.ts");
      p.getLanguageServiceForFile(otherFile);
      // refreshSourceFile should add it without throwing.
      expect(() => p.refreshSourceFile(file)).not.toThrow();
    });
  });

  describe("getProjectSourceFilePaths", () => {
    it("returns file paths as strings", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const paths = p.getProjectSourceFilePaths(dir);
      expect(Array.isArray(paths)).toBe(true);
      for (const fp of paths) {
        expect(typeof fp).toBe("string");
      }
    });

    it("includes source files from the project", () => {
      const dir = setup();
      const p = new TsMorphEngine();
      const paths = p.getProjectSourceFilePaths(dir);
      const utils = path.join(dir, "src/utils.ts");
      expect(paths.some((fp) => fp === utils || fp.endsWith("/src/utils.ts"))).toBe(true);
    });

    it("returns an empty array when the directory has no tsconfig and no source files", () => {
      const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-empty-"));
      try {
        const p = new TsMorphEngine();
        const paths = p.getProjectSourceFilePaths(tmpDir);
        expect(Array.isArray(paths)).toBe(true);
      } finally {
        fs.rmSync(tmpDir, { recursive: true, force: true });
      }
    });
  });

  describe("removeImportersOf", () => {
    it("delegates to tsRemoveImportersOf with workspace-expanded project graph", async () => {
      const dir = copyFixture(FIXTURES.deleteFileTs.name);
      dirs.push(dir);
      // TsMorphEngine(dir) expands the project graph to include all workspace files,
      // including tests/out-of-project.ts which is outside tsconfig.include.
      const p = new TsMorphEngine(dir);
      const target = path.join(dir, "src/target.ts");
      const scope = makeScope(dir);

      const count = await p.removeImportersOf(target, scope);

      // importer.ts: 2 (named import + type-only import)
      // barrel.ts:   2 (export * + named re-export)
      // tests/out-of-project.ts: 1 (included via expanded project graph)
      expect(count).toBe(5);
      expect(scope.modified).toContain(path.join(dir, "tests/out-of-project.ts"));
    });
  });

  describe("getFunction", () => {
    it("returns name and parameters for a named function", () => {
      const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-params-"));
      const file = path.join(tmpDir, "funcs.ts");
      fs.writeFileSync(
        file,
        "export function add(a: number, b: number): number { return a + b; }\n",
      );
      try {
        const p = new TsMorphEngine();
        const result = p.getFunction(file, "add");
        expect(result).toEqual({
          name: "add",
          parameters: [{ name: "a" }, { name: "b" }],
        });
      } finally {
        fs.rmSync(tmpDir, { recursive: true, force: true });
      }
    });

    it("returns empty parameters for a zero-arg function", () => {
      const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-params-"));
      const file = path.join(tmpDir, "funcs.ts");
      fs.writeFileSync(file, "export function noop(): void {}\n");
      try {
        const p = new TsMorphEngine();
        const result = p.getFunction(file, "noop");
        expect(result).toEqual({ name: "noop", parameters: [] });
      } finally {
        fs.rmSync(tmpDir, { recursive: true, force: true });
      }
    });

    it("returns undefined when the function does not exist", () => {
      const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "ts-params-"));
      const file = path.join(tmpDir, "funcs.ts");
      fs.writeFileSync(file, "export const x = 1;\n");
      try {
        const p = new TsMorphEngine();
        expect(p.getFunction(file, "nonExistent")).toBeUndefined();
      } finally {
        fs.rmSync(tmpDir, { recursive: true, force: true });
      }
    });
  });
});

src/operations/moveDirectory_tsMorphComp.source:
import * as fs from "node:fs";
import * as path from "node:path";
import { describe, expect } from "vitest";
import { FIXTURES, fileExists, readFile, fixtureTest as test } from "../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { makeMockCompiler } from "../ts-engine/__testHelpers__/mock-compiler.js";
import { TsMorphEngine } from "../ts-engine/engine.js";
import { moveDirectory } from "./moveDirectory.js";

function makeScope(dir: string): WorkspaceScope {
  return new WorkspaceScope(dir, new NodeFileSystem());
}

describe("moveDirectory", () => {
  describe("basic directory move", () => {
    test.override({ fixtureName: FIXTURES.moveDirTs.name });

    test("moves directory files and rewrites external imports", async ({ dir }) => {
      const compiler = new TsMorphEngine();

      const result = await moveDirectory(
        compiler,
        `${dir}/src/utils`,
        `${dir}/src/lib/helpers`,
        makeScope(dir),
      );

      const movedA = `${dir}/src/lib/helpers/a.ts`;
      const movedB = `${dir}/src/lib/helpers/b.ts`;

      expect(result.filesMoved).toContain(movedA);
      expect(result.filesMoved).toContain(movedB);

      expect(fileExists(dir, "src/lib/helpers/a.ts")).toBe(true);
      expect(fileExists(dir, "src/lib/helpers/b.ts")).toBe(true);
      expect(fileExists(dir, "src/utils/a.ts")).toBe(false);
      expect(fileExists(dir, "src/utils/b.ts")).toBe(false);

      const appContent = readFile(dir, "src/app.ts");
      expect(appContent).toContain("./lib/helpers/a");
      expect(appContent).toContain("./lib/helpers/b");
      expect(appContent).not.toContain("./utils/a");
      expect(appContent).not.toContain("./utils/b");

      // Key assertion: filesModified must include external files (app.ts), not just moved files
      expect(result.filesModified).toContain(`${dir}/src/app.ts`);

      // oldPath and newPath echoed
      expect(result.oldPath).toBe(`${dir}/src/utils`);
      expect(result.newPath).toBe(`${dir}/src/lib/helpers`);
    });

    test("includes moved files in filesModified", async ({ dir }) => {
      const compiler = new TsMorphEngine();

      const result = await moveDirectory(
        compiler,
        `${dir}/src/utils`,
        `${dir}/src/lib/helpers`,
        makeScope(dir),
      );

      expect(result.filesModified).toContain(`${dir}/src/lib/helpers/a.ts`);
      expect(result.filesModified).toContain(`${dir}/src/lib/helpers/b.ts`);
    });

    test("removes the old directory tree after a successful move", async ({ dir }) => {
      const compiler = new TsMorphEngine();
      const oldPath = `${dir}/src/utils`;

      await moveDirectory(compiler, oldPath, `${dir}/src/lib/helpers`, makeScope(dir));

      expect(fs.existsSync(oldPath)).toBe(false);
    });
  });

  describe("non-source files", () => {
    test.override({ fixtureName: FIXTURES.moveDirTs.name });

    test("moves non-source files (json, css) via plain filesystem copy", async ({ dir }) => {
      const compiler = new TsMorphEngine();

      fs.writeFileSync(path.join(dir, "src/utils/config.json"), '{"key": "value"}');
      fs.writeFileSync(path.join(dir, "src/utils/styles.css"), ".foo { color: red; }");

      const result = await moveDirectory(
        compiler,
        `${dir}/src/utils`,
        `${dir}/src/lib`,
        makeScope(dir),
      );

      expect(fileExists(dir, "src/lib/config.json")).toBe(true);
      expect(fileExists(dir, "src/lib/styles.css")).toBe(true);
      expect(fileExists(dir, "src/utils/config.json")).toBe(false);
      expect(fileExists(dir, "src/utils/styles.css")).toBe(false);

      expect(result.filesMoved).toContain(`${dir}/src/lib/config.json`);
      expect(result.filesMoved).toContain(`${dir}/src/lib/styles.css`);
      expect(result.filesModified).toContain(`${dir}/src/lib/config.json`);
      expect(result.filesModified).toContain(`${dir}/src/lib/styles.css`);
    });

    test("creates destination directory when moving non-source files into a new directory", async ({
      dir,
    }) => {
      const compiler = new TsMorphEngine();

      const assetsDir = path.join(dir, "assets");
      fs.mkdirSync(assetsDir);
      fs.writeFileSync(path.join(assetsDir, "logo.svg"), "<svg/>");
      fs.writeFileSync(path.join(assetsDir, "style.css"), "body { margin: 0; }");

      const result = await moveDirectory(
        compiler,
        assetsDir,
        `${dir}/public/static`,
        makeScope(dir),
      );

      expect(fileExists(dir, "public/static/logo.svg")).toBe(true);
      expect(fileExists(dir, "public/static/style.css")).toBe(true);
      expect(result.filesMoved).toContain(`${dir}/public/static/logo.svg`);
      expect(result.filesMoved).toContain(`${dir}/public/static/style.css`);
    });
  });

  describe("nested subdirectories", () => {
    test.override({ fixtureName: FIXTURES.moveDirTs.name });

    test("excludes SKIP_DIRS (node_modules) contents from the filesMoved result", async ({
      dir,
    }) => {
      const compiler = new TsMorphEngine();

      const fakeNodeModules = path.join(dir, "src/utils/node_modules");
      fs.mkdirSync(fakeNodeModules);
      fs.writeFileSync(path.join(fakeNodeModules, "dep.ts"), "export const x = 1;");

      const result = await moveDirectory(
        compiler,
        `${dir}/src/utils`,
        `${dir}/src/lib`,
        makeScope(dir),
      );

      // node_modules contents are not tracked in filesMoved (not source files)
      const movedBasenames = result.filesMoved.map((f) => path.basename(f));
      expect(movedBasenames).not.toContain("dep.ts");
      // The entire directory was atomically moved — node_modules physically moved with it
      expect(fileExists(dir, "src/lib/node_modules/dep.ts")).toBe(true);
    });
  });

  describe("edge cases", () => {
    test.override({ fixtureName: FIXTURES.moveDirTs.name });

    test("throws MOVE_INTO_SELF when oldPath and newPath are the same directory", async ({
      dir,
    }) => {
      const compiler = new TsMorphEngine();

      await expect(
        moveDirectory(compiler, `${dir}/src/utils`, `${dir}/src/utils`, makeScope(dir)),
      ).rejects.toMatchObject({ code: "MOVE_INTO_SELF" });
    });

    test("skips symlinks in directory enumeration", async ({ dir }) => {
      const compiler = new TsMorphEngine();

      const symlinkPath = path.join(dir, "src/utils/link-to-app");
      fs.symlinkSync(path.join(dir, "src/app.ts"), symlinkPath);

      const result = await moveDirectory(
        compiler,
        `${dir}/src/utils`,
        `${dir}/src/lib/helpers`,
        makeScope(dir),
      );

      const movedPaths = result.filesMoved.map((f) => path.basename(f));
      expect(movedPaths).not.toContain("link-to-app");
      expect(movedPaths).toContain("a.ts");
      expect(movedPaths).toContain("b.ts");
    });
  });

  describe("Vue import specifiers", () => {
    test.override({ fixtureName: FIXTURES.moveDirVue.name });

    test("physically moves .vue files to the destination when the directory moves", async ({
      dir,
    }) => {
      const compiler = new TsMorphEngine();

      await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/widgets`,
        makeScope(dir),
      );

      // .vue files must be physically present at the new path
      expect(fileExists(dir, "src/ui/widgets/Button.vue")).toBe(true);
      // Old location must be gone
      expect(fileExists(dir, "src/components/Button.vue")).toBe(false);
    });

    test("preserves .vue extension in moved file content — no .vue.ts artifact introduced", async ({
      dir,
    }) => {
      const compiler = new TsMorphEngine();

      await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/widgets`,
        makeScope(dir),
      );

      // The moved Button.vue must not have been corrupted by ts-morph's virtual .vue.ts mapping
      const buttonContent = readFile(dir, "src/ui/widgets/Button.vue");
      expect(buttonContent).not.toContain(".vue.ts");
      // Script content must be intact (defineProps is present in the original)
      expect(buttonContent).toContain("defineProps");
    });

    test("preserves .vue extension in moved file content for moduleResolution bundler", async ({
      dir,
    }) => {
      // The fixture uses moduleResolution: bundler — verify no extension stripping occurs
      const compiler = new TsMorphEngine();

      await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/widgets`,
        makeScope(dir),
      );

      const buttonContent = readFile(dir, "src/ui/widgets/Button.vue");
      // The .vue extension must not be stripped from file contents
      expect(buttonContent).not.toContain(".vue.ts");
      expect(buttonContent).toContain("<template>");
    });

    test("preserves intra-directory .ts imports within the moved directory", async ({ dir }) => {
      const compiler = new TsMorphEngine();

      await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/widgets`,
        makeScope(dir),
      );

      // Button.vue's import of ./utils should stay ./utils (both files moved together)
      const buttonContent = readFile(dir, "src/ui/widgets/Button.vue");
      expect(buttonContent).toContain("./utils");
      expect(buttonContent).not.toContain("components");
    });

    test("includes moved .vue files in filesMoved result", async ({ dir }) => {
      const compiler = new TsMorphEngine();

      const result = await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/widgets`,
        makeScope(dir),
      );

      // .vue files must appear in filesMoved even though the compiler doesn't track them
      expect(result.filesMoved).toContain(`${dir}/src/ui/widgets/Button.vue`);
    });

    test("does not introduce .vue.ts artifacts in any file after move", async ({ dir }) => {
      // ts-morph uses virtual .vue.ts stubs internally — these must never leak to disk
      const compiler = new TsMorphEngine();

      await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/widgets`,
        makeScope(dir),
      );

      // No .vue.ts file should exist anywhere in the fixture
      expect(fileExists(dir, "src/ui/widgets/Button.vue.ts")).toBe(false);
      expect(fileExists(dir, "src/components/Button.vue.ts")).toBe(false);
    });
  });

  describe("empty directory", () => {
    test.override({ fixtureName: FIXTURES.moveDirTs.name });

    test("returns empty arrays and no error for a directory with no files", async () => {
      const tmpRoot = fs.mkdtempSync(path.join(fs.realpathSync("/tmp"), "move-dir-empty-"));
      try {
        const emptyDir = path.join(tmpRoot, "source");
        fs.mkdirSync(emptyDir);
        const destDir = path.join(tmpRoot, "dest");
        const compiler = new TsMorphEngine();
        const scope = makeScope(tmpRoot);

        const result = await moveDirectory(compiler, emptyDir, destDir, scope);

        expect(result.filesMoved).toEqual([]);
        expect(result.filesModified).toEqual([]);
        expect(result.filesSkipped).toEqual([]);
        expect(result.oldPath).toBe(emptyDir);
        expect(result.newPath).toBe(destDir);
      } finally {
        fs.rmSync(tmpRoot, { recursive: true, force: true });
      }
    });
  });

  describe("error cases", () => {
    test.override({ fixtureName: FIXTURES.moveDirTs.name });

    test("throws FILE_NOT_FOUND when source does not exist", async ({ dir }) => {
      await expect(
        moveDirectory(
          new TsMorphEngine(),
          `${dir}/src/nonexistent`,
          `${dir}/src/dest`,
          makeScope(dir),
        ),
      ).rejects.toMatchObject({ code: "FILE_NOT_FOUND" });
    });

    test("throws NOT_A_DIRECTORY when source is a file", async ({ dir }) => {
      await expect(
        moveDirectory(new TsMorphEngine(), `${dir}/src/app.ts`, `${dir}/src/dest`, makeScope(dir)),
      ).rejects.toMatchObject({ code: "NOT_A_DIRECTORY" });
    });

    test("throws DESTINATION_EXISTS when destination is a non-empty directory", async ({ dir }) => {
      await expect(
        moveDirectory(new TsMorphEngine(), `${dir}/src/utils`, `${dir}/src`, makeScope(dir)),
      ).rejects.toMatchObject({ code: "DESTINATION_EXISTS" });
    });

    test("throws MOVE_INTO_SELF when newPath is inside oldPath", async ({ dir }) => {
      await expect(
        moveDirectory(
          new TsMorphEngine(),
          `${dir}/src/utils`,
          `${dir}/src/utils/subdir`,
          makeScope(dir),
        ),
      ).rejects.toMatchObject({ code: "MOVE_INTO_SELF" });
    });

    test("leaves all files at original paths when compiler.moveDirectory fails", async ({
      dir: _dir,
    }) => {
      const tmpRoot = fs.mkdtempSync(path.join(fs.realpathSync("/tmp"), "move-dir-atomic-"));
      try {
        const srcDir = path.join(tmpRoot, "src");
        const destDir = path.join(tmpRoot, "dest");
        fs.mkdirSync(srcDir);
        fs.writeFileSync(path.join(srcDir, "plain.ts"), "export const x = 1;");
        fs.writeFileSync(path.join(srcDir, "Component.vue"), "<template><div/></template>");

        const compiler = makeMockCompiler({
          moveDirectory: () => Promise.reject(new Error("compiler exploded")),
        });

        await expect(moveDirectory(compiler, srcDir, destDir, makeScope(tmpRoot))).rejects.toThrow(
          "compiler exploded",
        );

        expect(fs.existsSync(path.join(srcDir, "plain.ts"))).toBe(true);
        expect(fs.existsSync(path.join(srcDir, "Component.vue"))).toBe(true);
        expect(fs.existsSync(destDir)).toBe(false);
      } finally {
        fs.rmSync(tmpRoot, { recursive: true, force: true });
      }
    });
  });
});

