import * as fs from "node:fs";
import * as path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import {
  cleanup,
  copyFixture,
  FIXTURES,
  fileExists,
  readFile,
} from "../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { TsMorphEngine } from "./engine.js";
import { tsMoveDirectory } from "./move-directory.js";

function makeScope(dir: string): WorkspaceScope {
  return new WorkspaceScope(dir, new NodeFileSystem());
}

describe("tsMoveDirectory", () => {
  const dirs: string[] = [];
  afterEach(() => dirs.splice(0).forEach(cleanup));

  describe("source file handling", () => {
    it("physically moves source files and rewrites external imports", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);
      const engine = new TsMorphEngine();

      const result = await tsMoveDirectory(
        engine,
        `${dir}/src/utils`,
        `${dir}/src/lib/helpers`,
        makeScope(dir),
      );

      expect(fileExists(dir, "src/lib/helpers/a.ts")).toBe(true);
      expect(fileExists(dir, "src/lib/helpers/b.ts")).toBe(true);
      expect(fileExists(dir, "src/utils/a.ts")).toBe(false);
      expect(fileExists(dir, "src/utils/b.ts")).toBe(false);

      const appContent = readFile(dir, "src/app.ts");
      expect(appContent).toContain("./lib/helpers/a");
      expect(appContent).toContain("./lib/helpers/b");
      expect(appContent).not.toContain("./utils/a");
      expect(appContent).not.toContain("./utils/b");

      expect(result.filesMoved).toContain(`${dir}/src/lib/helpers/a.ts`);
      expect(result.filesMoved).toContain(`${dir}/src/lib/helpers/b.ts`);
    });

    it("records all moved source files as modified in scope", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);
      const engine = new TsMorphEngine();

      await tsMoveDirectory(engine, `${dir}/src/utils`, `${dir}/src/lib/helpers`, makeScope(dir));

      const scope = makeScope(dir);
      const result = await tsMoveDirectory(
        new TsMorphEngine(),
        `${dir}/src/lib/helpers`,
        `${dir}/src/lib/utils2`,
        scope,
      );

      expect(scope.modified).toContain(`${dir}/src/lib/utils2/a.ts`);
      expect(scope.modified).toContain(`${dir}/src/lib/utils2/b.ts`);
      expect(result.filesMoved).toContain(`${dir}/src/lib/utils2/a.ts`);
    });

    it("preserves intra-directory imports unchanged after move", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);
      const engine = new TsMorphEngine();

      await tsMoveDirectory(engine, `${dir}/src/utils`, `${dir}/src/lib`, makeScope(dir));

      // b.ts imports ./a (intra-directory) — must remain ./a after the move
      const bContent = readFile(dir, "src/lib/b.ts");
      expect(bContent).toContain('"./a"');
      expect(bContent).not.toContain("utils");
    });
  });

  describe("non-source file handling", () => {
    it("includes non-source files in filesMoved via atomic OS rename", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);

      fs.writeFileSync(path.join(dir, "src/utils/config.json"), '{"key": "value"}');
      fs.writeFileSync(path.join(dir, "src/utils/styles.css"), ".foo { color: red; }");

      const engine = new TsMorphEngine();
      const result = await tsMoveDirectory(
        engine,
        `${dir}/src/utils`,
        `${dir}/src/lib`,
        makeScope(dir),
      );

      expect(fileExists(dir, "src/lib/config.json")).toBe(true);
      expect(fileExists(dir, "src/lib/styles.css")).toBe(true);
      expect(result.filesMoved).toContain(`${dir}/src/lib/config.json`);
      expect(result.filesMoved).toContain(`${dir}/src/lib/styles.css`);
    });

    it("moves non-source-only directories with no source files", async () => {
      const tmpRoot = fs.mkdtempSync(path.join(fs.realpathSync("/tmp"), "ts-move-dir-assets-"));
      dirs.push(tmpRoot);

      const assetsDir = path.join(tmpRoot, "assets");
      fs.mkdirSync(assetsDir);
      fs.writeFileSync(path.join(assetsDir, "logo.svg"), "<svg/>");
      fs.writeFileSync(path.join(assetsDir, "style.css"), "body { margin: 0; }");

      const engine = new TsMorphEngine();
      const result = await tsMoveDirectory(
        engine,
        assetsDir,
        path.join(tmpRoot, "public"),
        makeScope(tmpRoot),
      );

      expect(fs.existsSync(path.join(tmpRoot, "public/logo.svg"))).toBe(true);
      expect(fs.existsSync(path.join(tmpRoot, "public/style.css"))).toBe(true);
      expect(result.filesMoved).toContain(path.join(tmpRoot, "public/logo.svg"));
      expect(result.filesMoved).toContain(path.join(tmpRoot, "public/style.css"));
    });
  });

  describe("empty directory", () => {
    it("returns empty filesMoved for a directory with no files", async () => {
      const tmpRoot = fs.mkdtempSync(path.join(fs.realpathSync("/tmp"), "ts-move-dir-empty-"));
      dirs.push(tmpRoot);

      const emptyDir = path.join(tmpRoot, "source");
      fs.mkdirSync(emptyDir);
      const engine = new TsMorphEngine();

      const result = await tsMoveDirectory(
        engine,
        emptyDir,
        path.join(tmpRoot, "dest"),
        makeScope(tmpRoot),
      );

      expect(result.filesMoved).toEqual([]);
    });
  });

  describe("SKIP_DIRS exclusion", () => {
    it("does not include node_modules contents in filesMoved", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);

      const fakeNodeModules = path.join(dir, "src/utils/node_modules");
      fs.mkdirSync(fakeNodeModules);
      fs.writeFileSync(path.join(fakeNodeModules, "dep.ts"), "export const x = 1;");

      const engine = new TsMorphEngine();
      const result = await tsMoveDirectory(
        engine,
        `${dir}/src/utils`,
        `${dir}/src/lib`,
        makeScope(dir),
      );

      const movedBasenames = result.filesMoved.map((f) => path.basename(f));
      expect(movedBasenames).not.toContain("dep.ts");
      expect(movedBasenames).toContain("a.ts");
      expect(movedBasenames).toContain("b.ts");
    });
  });
});

describe("TsMorphEngine.moveDirectory", () => {
  const dirs: string[] = [];
  afterEach(() => dirs.splice(0).forEach(cleanup));

  describe("scope records modified files", () => {
    it("records moved and externally-modified files in scope", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);
      const compiler = new TsMorphEngine();
      const scope = makeScope(dir);

      await compiler.moveDirectory(`${dir}/src/utils`, `${dir}/src/lib`, scope);

      // External importer rewritten by compiler
      expect(scope.modified).toContain(`${dir}/src/app.ts`);
      // Moved files also recorded
      expect(scope.modified).toContain(`${dir}/src/lib/a.ts`);
      expect(scope.modified).toContain(`${dir}/src/lib/b.ts`);
    });

    it("does not record unchanged files unrelated to the move", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);
      const compiler = new TsMorphEngine();
      const scope = makeScope(dir);

      await compiler.moveDirectory(`${dir}/src/utils`, `${dir}/src/lib`, scope);

      // unrelated.ts has no imports from utils/ so it should not be in scope
      expect(scope.modified).not.toContain(`${dir}/src/unrelated.ts`);
    });
  });

  describe("empty directory", () => {
    it("does not record any files in scope when directory has no source files", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);

      const emptyDir = `${dir}/src/empty-utils`;
      fs.mkdirSync(emptyDir, { recursive: true });

      const compiler = new TsMorphEngine();
      const scope = makeScope(dir);

      await compiler.moveDirectory(emptyDir, `${dir}/src/empty-lib`, scope);

      expect(scope.modified).toHaveLength(0);
    });
  });

  describe("project cache invalidation", () => {
    it("subsequent moveDirectory calls on the same compiler instance work correctly", async () => {
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);
      const compiler = new TsMorphEngine();

      // First move: utils -> lib
      const scope1 = makeScope(dir);
      const result1 = await compiler.moveDirectory(`${dir}/src/utils`, `${dir}/src/lib`, scope1);
      expect(result1.filesMoved).toContain(`${dir}/src/lib/a.ts`);

      // Second move on the same compiler: lib/nested -> lib/sub
      // This verifies the project cache was invalidated after the first move
      const scope2 = makeScope(dir);
      const result2 = await compiler.moveDirectory(
        `${dir}/src/lib/nested`,
        `${dir}/src/lib/sub`,
        scope2,
      );
      expect(result2.filesMoved).toContain(`${dir}/src/lib/sub/c.ts`);
      expect(result2.filesMoved).not.toContain(`${dir}/src/lib/nested/c.ts`);
    });
  });

  describe("ESM .js extension preservation", () => {
    it("preserves .js extensions in import specifiers after directory move", async () => {
      const dir = copyFixture(FIXTURES.moveDirTsEsm.name);
      dirs.push(dir);
      const compiler = new TsMorphEngine();
      const scope = makeScope(dir);

      await compiler.moveDirectory(`${dir}/src/utils`, `${dir}/src/lib`, scope);

      // External importer: .js extensions must be preserved
      const appContent = readFile(dir, "src/app.ts");
      expect(appContent).toContain("./lib/a.js");
      expect(appContent).toContain("./lib/b.js");
      expect(appContent).not.toContain("./utils/");

      // Internal import within moved directory: b.ts imports from a.ts with .js extension
      // Since both files moved together, the relative path stays the same
      const bContent = readFile(dir, "src/lib/b.ts");
      expect(bContent).toContain("./a.js");
      expect(bContent).not.toContain("./utils/");
    });
  });

  describe("sub-project boundary", () => {
    it("does not rewrite internal imports when moved directory has its own tsconfig", async () => {
      const dir = copyFixture(FIXTURES.moveDirSubproject.name);
      dirs.push(dir);
      const compiler = new TsMorphEngine();
      const scope = makeScope(dir);

      await compiler.moveDirectory(`${dir}/src/pkg`, `${dir}/src/library`, scope);

      const indexContent = readFile(dir, "src/library/index.ts");
      expect(indexContent).toContain("./utils");
      expect(indexContent).not.toContain("pkg");

      const appContent = readFile(dir, "src/app.ts");
      expect(appContent).toContain("./library/index");
      expect(appContent).not.toContain("./pkg/");
    });
  });

  describe("files excluded from tsconfig project", () => {
    it("includes TS files on disk in the moved directory even when excluded from tsconfig", async () => {
      // Copy the fixture and update tsconfig to exclude utils/ — simulating
      // files that exist on disk but are not in the ts-morph project
      const dir = copyFixture(FIXTURES.moveDirTs.name);
      dirs.push(dir);

      // Rewrite tsconfig to only include app.ts — utils/*.ts are excluded
      fs.writeFileSync(
        path.join(dir, "tsconfig.json"),
        JSON.stringify({ compilerOptions: { strict: true }, include: ["src/app.ts"] }),
      );

      // Add a nested file to the excluded utils directory for SKIP_DIRS coverage
      const nmDir = path.join(dir, "src/utils/node_modules");
      fs.mkdirSync(nmDir, { recursive: true });
      fs.writeFileSync(path.join(nmDir, "skip.ts"), "export const x = 1;\n");

      const compiler = new TsMorphEngine();
      const scope = makeScope(dir);

      const result = await compiler.moveDirectory(`${dir}/src/utils`, `${dir}/src/lib`, scope);

      // enumerateSourceFiles should have added the excluded files to the project
      expect(result.filesMoved).toContain(`${dir}/src/lib/a.ts`);
      expect(result.filesMoved).toContain(`${dir}/src/lib/b.ts`);
      expect(result.filesMoved).toContain(`${dir}/src/lib/nested/c.ts`);
      // node_modules is skipped by SKIP_DIRS
      expect(result.filesMoved).not.toContain(`${dir}/src/lib/node_modules/skip.ts`);
      // External importer should be rewritten even though utils/ was excluded from tsconfig
      const appContent = readFile(dir, "src/app.ts");
      expect(appContent).toContain("./lib/a");
      expect(appContent).not.toContain("./utils/a");
    });
  });
});

src/operations/moveDirectory_volarCompil.source:
import { describe, expect } from "vitest";
import { FIXTURES, fileExists, readFile, fixtureTest as test } from "../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { VolarEngine } from "../plugins/vue/engine.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { TsMorphEngine } from "../ts-engine/engine.js";
import { moveDirectory } from "./moveDirectory.js";

function makeScope(dir: string): WorkspaceScope {
  return new WorkspaceScope(dir, new NodeFileSystem());
}

describe("moveDirectory action - VolarEngine integration", () => {
  test.override({ fixtureName: FIXTURES.moveDirVueExternal.name });

  describe("external .ts files importing moved .vue components", () => {
    test("updates path-alias import specifier in external .ts file after moving directory", async ({
      dir,
    }) => {
      const compiler = new VolarEngine(new TsMorphEngine());

      await moveDirectory(compiler, `${dir}/src/components`, `${dir}/src/ui`, makeScope(dir));

      const appTs = readFile(dir, "src/app.ts");
      expect(appTs).not.toContain("@/components/Button.vue");
    });

    test("updates import specifier in external .ts file after moving directory with .vue files", async ({
      dir,
    }) => {
      const compiler = new VolarEngine(new TsMorphEngine());

      await moveDirectory(compiler, `${dir}/src/components`, `${dir}/src/ui`, makeScope(dir));

      // The moved .vue file must be at the new location
      expect(fileExists(dir, "src/ui/Button.vue")).toBe(true);
      expect(fileExists(dir, "src/components/Button.vue")).toBe(false);

      // The external .ts file must have its import specifier updated
      const appTs = readFile(dir, "src/app.ts");
      expect(appTs).toContain("./ui/Button.vue");
      expect(appTs).not.toContain("./components/Button.vue");
    });

    test("updates import specifier in external .ts file when moving into a nested destination", async ({
      dir,
    }) => {
      const compiler = new VolarEngine(new TsMorphEngine());

      await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/widgets`,
        makeScope(dir),
      );

      const appTs = readFile(dir, "src/app.ts");
      expect(appTs).toContain("./ui/widgets/Button.vue");
      expect(appTs).not.toContain("./components/Button.vue");
    });
  });

  describe("external .vue files importing from moved directory", () => {
    test("updates import specifier in external .vue file after moving a composables directory", async ({
      dir,
    }) => {
      const compiler = new VolarEngine(new TsMorphEngine());

      await moveDirectory(compiler, `${dir}/src/composables`, `${dir}/src/hooks`, makeScope(dir));

      // The moved .ts file must be at the new location
      expect(fileExists(dir, "src/hooks/useCounter.ts")).toBe(true);
      expect(fileExists(dir, "src/composables/useCounter.ts")).toBe(false);

      // The external .vue file must have its import specifier updated
      const appVue = readFile(dir, "src/App.vue");
      expect(appVue).toContain("./hooks/useCounter");
      expect(appVue).not.toContain("./composables/useCounter");
    });

    test("updates import specifier in external .vue file after moving a components directory with .vue files", async ({
      dir,
    }) => {
      const compiler = new VolarEngine(new TsMorphEngine());

      await moveDirectory(compiler, `${dir}/src/components`, `${dir}/src/ui`, makeScope(dir));

      // App.vue also imports Button.vue from components — it must be updated
      const appVue = readFile(dir, "src/App.vue");
      expect(appVue).toContain("./ui/Button.vue");
      expect(appVue).not.toContain("./components/Button.vue");
    });
  });

  describe("moved .vue files with external relative imports", () => {
    test("updates relative import in moved .vue file that points outside the moved directory", async ({
      dir,
    }) => {
      const compiler = new VolarEngine(new TsMorphEngine());

      // Button.vue imports '../lib/helper'; after moving components/ → ui/components/
      // the import should become '../../lib/helper'
      await moveDirectory(
        compiler,
        `${dir}/src/components`,
        `${dir}/src/ui/components`,
        makeScope(dir),
      );

      const buttonVue = readFile(dir, "src/ui/components/Button.vue");
      expect(buttonVue).toContain("../../lib/helper");
      // The single-depth path must not appear as a standalone specifier
      // (note: "../../lib/helper" contains "../lib/helper" as a substring,
      // so we check the full depth is correct)
      expect(buttonVue).not.toContain('"../lib/helper"');
      expect(buttonVue).not.toContain("'../lib/helper'");
    });

    test("does not rewrite intra-directory imports between moved .vue files", async ({ dir }) => {
      const compiler = new VolarEngine(new TsMorphEngine());

      // Moving composables/ — useCounter.ts has no intra-dir imports, so this just
      // verifies the composable content is intact after the move
      await moveDirectory(compiler, `${dir}/src/composables`, `${dir}/src/hooks`, makeScope(dir));

      const composable = readFile(dir, "src/hooks/useCounter.ts");
      expect(composable).toContain("useCounter");
      expect(composable).toContain("ref");
    });
  });
});

src/operations/getTypeErrors.test.ts.source:
import { afterAll, beforeAll, describe, expect, it } from "vitest";
import { cleanup, copyFixture, FIXTURES } from "../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { TsMorphEngine } from "../ts-engine/engine.js";
import { getTypeErrors } from "./getTypeErrors.js";

function makeScope(dir: string): WorkspaceScope {
  return new WorkspaceScope(dir, new NodeFileSystem());
}

describe("getTypeErrors operation", () => {
  describe("single file mode (file param provided)", () => {
    let dir: string;
    beforeAll(() => {
      dir = copyFixture(FIXTURES.tsErrors.name);
    });
    afterAll(() => cleanup(dir));

    it("returns type errors with correct shape for a file with errors", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, `${dir}/src/broken.ts`, makeScope(dir));

      // broken.ts has exactly 3 deliberate errors
      expect(result.errorCount).toBe(3);
      expect(result.diagnostics).toHaveLength(3);
      expect(result.truncated).toBe(false);

      // Every diagnostic must have the required shape
      for (const diag of result.diagnostics) {
        expect(diag.file).toBe(`${dir}/src/broken.ts`);
        expect(diag.line).toBeGreaterThan(0);
        expect(diag.col).toBeGreaterThan(0);
        expect(diag.code).toBeGreaterThan(0);
        expect(typeof diag.code).toBe("number");
        expect(diag.message.length).toBeGreaterThan(0);
      }
    });

    it("pins the exact error codes, positions and messages for broken.ts", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, `${dir}/src/broken.ts`, makeScope(dir));

      const diags = result.diagnostics.slice().sort((a, b) => a.line - b.line);

      expect(diags[0]).toMatchObject({
        line: 6,
        col: 17,
        code: 2345,
        message: "Argument of type 'string' is not assignable to parameter of type 'number'.",
      });
      expect(diags[1]).toMatchObject({
        line: 8,
        col: 7,
        code: 2322,
        message: "Type 'number' is not assignable to type 'string'.",
      });
      expect(diags[2]).toMatchObject({
        line: 10,
        col: 7,
        code: 2322,
        message: "Type 'number' is not assignable to type 'boolean'.",
      });
    });

    it("returns only the top-level message for chained diagnostics, not the full chain", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, `${dir}/src/chained-error.ts`, makeScope(dir));

      expect(result.diagnostics).toHaveLength(1);
      const { message } = result.diagnostics[0];

      // Top-level node only: the function type mismatch
      expect(message).toContain("not assignable to type '(x: string) => number'");
      // Chain levels must NOT be present — they balloon message size for complex generic types
      expect(message).not.toContain("Types of parameters");
      expect(message).not.toContain("Type 'string' is not assignable to type 'number'");
    });

    it("returns empty diagnostics for a clean file", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, `${dir}/src/clean.ts`, makeScope(dir));

      expect(result.diagnostics).toHaveLength(0);
      expect(result.errorCount).toBe(0);
      expect(result.truncated).toBe(false);
    });

    it("throws FILE_NOT_FOUND for a non-existent file", async () => {
      const compiler = new TsMorphEngine();

      await expect(
        getTypeErrors(compiler, `${dir}/src/doesNotExist.ts`, makeScope(dir)),
      ).rejects.toMatchObject({ code: "FILE_NOT_FOUND" });
    });

    it("throws WORKSPACE_VIOLATION for a file outside the workspace", async () => {
      const compiler = new TsMorphEngine();

      await expect(getTypeErrors(compiler, "/etc/hosts", makeScope(dir))).rejects.toMatchObject({
        code: "WORKSPACE_VIOLATION",
      });
    });

    it("errorCount equals diagnostics.length when not truncated", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, `${dir}/src/broken.ts`, makeScope(dir));

      // When not truncated, errorCount is the true total and equals diagnostics.length
      expect(result.errorCount).toBe(result.diagnostics.length);
      expect(result.truncated).toBe(false);
    });

    it("caps at 100 and sets truncated=true when a single file has more than 100 errors", async () => {
      const compiler = new TsMorphEngine();

      // many-errors.ts has 105 deliberate type errors
      const result = await getTypeErrors(compiler, `${dir}/src/many-errors.ts`, makeScope(dir));

      expect(result.truncated).toBe(true);
      expect(result.diagnostics).toHaveLength(100);
      expect(result.errorCount).toBe(105);
    });

    it("is not truncated and errorCount equals 100 when a file has exactly 100 errors", async () => {
      const ts100Dir = copyFixture(FIXTURES.ts100Errors.name);
      try {
        const compiler = new TsMorphEngine();

        const result = await getTypeErrors(
          compiler,
          `${ts100Dir}/src/exactly-100.ts`,
          makeScope(ts100Dir),
        );

        expect(result.truncated).toBe(false);
        expect(result.errorCount).toBe(100);
        expect(result.diagnostics).toHaveLength(100);
      } finally {
        cleanup(ts100Dir);
      }
    });
  });

  describe("project-wide mode (no file param)", () => {
    let dir: string;
    beforeAll(() => {
      dir = copyFixture(FIXTURES.tsErrors.name);
    });
    afterAll(() => cleanup(dir));

    it("returns errors from all files in the project", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, undefined, makeScope(dir));

      // broken.ts (3 errors) + many-errors.ts (105 errors) = 108 total, so truncated
      expect(result.errorCount).toBeGreaterThan(100);
      expect(result.diagnostics).toHaveLength(100);
      expect(result.truncated).toBe(true);
    });

    it("caps at 100 and sets truncated=true; errorCount reflects the full total", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, undefined, makeScope(dir));

      expect(result.truncated).toBe(true);
      expect(result.diagnostics).toHaveLength(100);
      // errorCount is the total found, not the capped count
      expect(result.errorCount).toBeGreaterThan(100);
      expect(result.errorCount).toBeGreaterThan(result.diagnostics.length);
    });

    it("is not truncated and errorCount equals 100 when the project has exactly 100 errors", async () => {
      const ts100Dir = copyFixture(FIXTURES.ts100Errors.name);
      try {
        const compiler = new TsMorphEngine();

        const result = await getTypeErrors(compiler, undefined, makeScope(ts100Dir));

        expect(result.truncated).toBe(false);
        expect(result.errorCount).toBe(100);
        expect(result.diagnostics).toHaveLength(100);
      } finally {
        cleanup(ts100Dir);
      }
    });

    it("returns empty result for a project with no errors", async () => {
      const simpleDir = copyFixture(FIXTURES.simpleTs.name);
      try {
        const compiler = new TsMorphEngine();

        const result = await getTypeErrors(compiler, undefined, makeScope(simpleDir));

        expect(result.diagnostics).toHaveLength(0);
        expect(result.errorCount).toBe(0);
        expect(result.truncated).toBe(false);
      } finally {
        cleanup(simpleDir);
      }
    });

    it("each diagnostic in project-wide results has the correct shape", async () => {
      const compiler = new TsMorphEngine();

      const result = await getTypeErrors(compiler, undefined, makeScope(dir));

      for (const diag of result.diagnostics) {
        expect(typeof diag.file).toBe("string");
        expect(diag.file.length).toBeGreaterThan(0);
        expect(diag.line).toBeGreaterThan(0);
        expect(diag.col).toBeGreaterThan(0);
        expect(typeof diag.code).toBe("number");
        expect(diag.code).toBeGreaterThan(0);
        expect(typeof diag.message).toBe("string");
        expect(diag.message.length).toBeGreaterThan(0);
      }
    });
  });
});

src/ts-engine/transitive-imports.test.ts.source:
import { Project } from "ts-morph";
import { describe, expect, it } from "vitest";
import { collectTransitiveImports } from "./transitive-imports.js";

function makeProject() {
  return new Project({ useInMemoryFileSystem: true });
}

describe("collectTransitiveImports", () => {
  describe("basic import carry", () => {
    it("returns import entry when declaration references a named import", () => {
      const project = makeProject();
      project.createSourceFile("/types.ts", "export type Bar = { value: string };\n");
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { Bar } from "./types";\nexport function Foo(b: Bar): string { return b.value; }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].resolvedAbsPath).toBe("/types.ts");
      expect(result[0].namedImports).toEqual([{ name: "Bar" }]);
    });

    it("returns empty array when declaration has no external references", () => {
      const project = makeProject();
      const srcSF = project.createSourceFile(
        "/source.ts",
        "export function Foo(): string { return 'hello'; }\n",
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(0);
    });
  });

  describe("alias preservation", () => {
    it("preserves import alias when the declaration uses an aliased import", () => {
      const project = makeProject();
      project.createSourceFile("/types.ts", "export type Bar = { value: string };\n");
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { Bar as B } from "./types";\nexport function Foo(b: B): string { return b.value; }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].namedImports).toEqual([{ name: "Bar", alias: "B" }]);
    });
  });

  describe("deduplication", () => {
    it("deduplicates multiple references to the same import from the same module", () => {
      const project = makeProject();
      project.createSourceFile(
        "/types.ts",
        "export type Bar = { value: string };\nexport type Baz = { count: number };\n",
      );
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { Bar, Baz } from "./types";\nexport function Foo(b: Bar, c: Baz): string { return b.value + c.count; }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].resolvedAbsPath).toBe("/types.ts");
      expect(result[0].namedImports).toHaveLength(2);
      const names = result[0].namedImports.map((ni) => ni.name);
      expect(names).toContain("Bar");
      expect(names).toContain("Baz");
    });

    it("does not duplicate a named import referenced multiple times in the declaration", () => {
      const project = makeProject();
      project.createSourceFile("/types.ts", "export type Bar = { value: string };\n");
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { Bar } from "./types";\nexport function Foo(a: Bar, b: Bar): string { return a.value + b.value; }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].namedImports).toHaveLength(1);
    });
  });

  describe("skip locally-defined identifiers", () => {
    it("does not carry imports for names defined locally in the source file", () => {
      const project = makeProject();
      const srcSF = project.createSourceFile(
        "/source.ts",
        "type LocalType = { value: string };\nexport function Foo(b: LocalType): string { return b.value; }\n",
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(0);
    });
  });

  describe("skip TypeScript lib types", () => {
    it("does not carry built-in TypeScript library types", () => {
      const project = makeProject();
      const srcSF = project.createSourceFile(
        "/source.ts",
        "export function Foo(items: string[]): Promise<number> { return Promise.resolve(items.length); }\n",
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(0);
    });
  });

  describe("multiple imports from same module", () => {
    it("groups multiple named imports from the same module into a single entry", () => {
      const project = makeProject();
      project.createSourceFile("/shared.ts", "export type A = string;\nexport type B = number;\n");
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { A, B } from "./shared";\nexport function Foo(a: A, b: B): string { return String(b); }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].resolvedAbsPath).toBe("/shared.ts");
    });
  });

  describe("non-aliased import has no alias property", () => {
    it("omits alias field when import has no alias", () => {
      const project = makeProject();
      project.createSourceFile("/types.ts", "export type Bar = { value: string };\n");
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { Bar } from "./types";\nexport function Foo(b: Bar): string { return b.value; }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result[0].namedImports[0]).not.toHaveProperty("alias");
    });
  });

  describe("import from different module not carried for local identifier match", () => {
    it("does not carry an import whose resolved path differs from the identifier's resolved path", () => {
      const project = makeProject();
      project.createSourceFile("/a.ts", "export type X = string;\n");
      project.createSourceFile("/b.ts", "export type X = number;\n");
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { X } from "./a";\nexport function Foo(x: X): string { return String(x); }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].resolvedAbsPath).toBe("/a.ts");
    });
  });

  describe("identifier matching uses local alias name", () => {
    it("matches on the alias name, not the original exported name", () => {
      const project = makeProject();
      project.createSourceFile("/types.ts", "export type Bar = { value: string };\n");
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { Bar as Renamed } from "./types";\nexport function Foo(b: Renamed): string { return b.value; }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].namedImports).toEqual([{ name: "Bar", alias: "Renamed" }]);
    });
  });

  describe("deduplication across mixed known and new names", () => {
    it("adds only the new name when one import is already tracked and the other is not", () => {
      const project = makeProject();
      project.createSourceFile(
        "/types.ts",
        "export type A = string;\nexport type B = number;\nexport type C = boolean;\n",
      );
      const srcSF = project.createSourceFile(
        "/source.ts",
        'import { A, B, C } from "./types";\nexport function Foo(a: A, b: B, c: C): string { return String(a) + String(b) + String(c); }\n',
      );
      const declStmt = srcSF.getFunctionOrThrow("Foo");

      const result = collectTransitiveImports(srcSF, declStmt);

      expect(result).toHaveLength(1);
      expect(result[0].namedImports).toHaveLength(3);
      const names = result[0].namedImports.map((ni) => ni.name);
      expect(names).toContain("A");
      expect(names).toContain("B");
      expect(names).toContain("C");
    });
  });
});

src/ts-engine/extract-function.test.ts.source:
import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import { cleanup, copyFixture, FIXTURES } from "../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { VolarEngine } from "../plugins/vue/engine.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { TsMorphEngine } from "./engine.js";
import { tsExtractFunction } from "./extract-function.js";

describe("tsExtractFunction", () => {
  const dirs: string[] = [];
  afterEach(() => dirs.splice(0).forEach(cleanup));

  function makeTempDir(): string {
    const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-ts-extractfn-"));
    dirs.push(dir);
    fs.writeFileSync(
      path.join(dir, "tsconfig.json"),
      JSON.stringify({ compilerOptions: { strict: true }, include: ["src/**/*.ts"] }),
    );
    fs.mkdirSync(path.join(dir, "src"), { recursive: true });
    return dir;
  }

  function makeScope(dir: string): WorkspaceScope {
    return new WorkspaceScope(dir, new NodeFileSystem());
  }

  it("creates a new function and replaces the selection with a call", async () => {
    const dir = makeTempDir();
    const src = `export function outer(n: number): void {
  const doubled = n * 2;
  const msg = \`Value is \${doubled}\`;
  console.log(msg);
}
`;
    const filePath = path.join(dir, "src/target.ts");
    fs.writeFileSync(filePath, src);

    const result = await tsExtractFunction(
      new TsMorphEngine(),
      filePath,
      2,
      3, // startLine, startCol
      4,
      19, // endLine, endCol (end of "console.log(msg);", inclusive of semicolon)
      "logDoubled",
      makeScope(dir),
    );

    expect(result.filesModified).toEqual([filePath]);
    expect(result.filesSkipped).toEqual([]);
    expect(result.functionName).toBe("logDoubled");
    // The file must contain the new function
    const written = fs.readFileSync(filePath, "utf8");
    expect(written).toContain("function logDoubled");
    // The outer function body must contain a call to logDoubled
    expect(written).toContain("logDoubled(");
  });

  it("filesModified contains exactly the source file — no other files are written", async () => {
    const dir = makeTempDir();
    const src = `export function run(x: number): number {
  const result = x + 1;
  return result;
}
`;
    const filePath = path.join(dir, "src/target.ts");
    fs.writeFileSync(filePath, src);

    const result = await tsExtractFunction(
      new TsMorphEngine(),
      filePath,
      2,
      3,
      2,
      22, // end of "const result = x + 1;"
      "increment",
      makeScope(dir),
    );

    expect(result.filesModified).toHaveLength(1);
    expect(result.filesModified[0]).toBe(filePath);
    expect(result.filesSkipped).toEqual([]);
  });

  it("parameterCount reflects the number of parameters inferred by the compiler", async () => {
    const dir = makeTempDir();
    // Selection references two outer-scope variables → extracted fn should have 2 params
    const src = `export function compute(x: number, y: number): number {
  const sum = x + y;
  return sum;
}
`;
    const filePath = path.join(dir, "src/target.ts");
    fs.writeFileSync(filePath, src);

    const result = await tsExtractFunction(
      new TsMorphEngine(),
      filePath,
      2,
      15, // col of 'x'
      2,
      19, // col after 'y'
      "add",
      makeScope(dir),
    );

    expect(result.parameterCount).toBeGreaterThanOrEqual(2);
    const written = fs.readFileSync(filePath, "utf8");
    expect(written).toContain("function add(");
  });

  it("parameterCount is 0 when the extracted code references no outer-scope variables", async () => {
    const dir = makeTempDir();
    const src = `export function run(): number {
  const val = 42;
  return val;
}
`;
    const filePath = path.join(dir, "src/target.ts");
    fs.writeFileSync(filePath, src);

    // Extract "42" (a literal — no outer references)
    const result = await tsExtractFunction(
      new TsMorphEngine(),
      filePath,
      2,
      15, // col of '4' in '42'
      2,
      16, // col of '2' in '42'
      "magicNumber",
      makeScope(dir),
    );

    expect(result.parameterCount).toBe(0);
  });

  it("extracted function uses the provided name, not a compiler-generated default", async () => {
    const dir = makeTempDir();
    const src = `export function wrapper(a: number, b: number): number {
  const product = a * b;
  return product;
}
`;
    const filePath = path.join(dir, "src/target.ts");
    fs.writeFileSync(filePath, src);

    const result = await tsExtractFunction(
      new TsMorphEngine(),
      filePath,
      2,
      19, // col of 'a'
      2,
      23, // col after 'b'
      "multiply",
      makeScope(dir),
    );

    expect(result.functionName).toBe("multiply");
    const written = fs.readFileSync(filePath, "utf8");
    expect(written).toContain("function multiply(");
    // The call site also uses the provided name
    expect(written).toContain("multiply(");
    // Must NOT contain the compiler default name
    expect(written).not.toContain("newFunction");
    expect(written).not.toContain("extracted");
  });

  it("both the declaration and the call site use the provided name", async () => {
    const dir = makeTempDir();
    const src = `export function outer(): void {
  const x = 1;
  const y = 2;
  console.log(x + y);
}
`;
    const filePath = path.join(dir, "src/target.ts");
    fs.writeFileSync(filePath, src);

    await tsExtractFunction(
      new TsMorphEngine(),
      filePath,
      4,
      3,
      4,
      22, // "console.log(x + y);"
      "printSum",
      makeScope(dir),
    );

    const written = fs.readFileSync(filePath, "utf8");
    // Count occurrences: both declaration and call site
    const occurrences = (written.match(/printSum/g) ?? []).length;
    expect(occurrences).toBeGreaterThanOrEqual(2);
  });

  it("throws NOT_SUPPORTED when no extractable code exists at the given range", async () => {
    const dir = copyFixture(FIXTURES.simpleTs.name);
    dirs.push(dir);
    const filePath = path.join(dir, "src/utils.ts");

    // Line 1 col 1 to line 1 col 1 — empty range, nothing to extract
    await expect(
      tsExtractFunction(new TsMorphEngine(), filePath, 1, 1, 1, 1, "myFn", makeScope(dir)),
    ).rejects.toMatchObject({ code: "NOT_SUPPORTED" });
  });
});

describe("VolarEngine.extractFunction", () => {
  it("throws NOT_SUPPORTED for a .vue path", async () => {
    const engine = new VolarEngine(new TsMorphEngine());
    const scope = new WorkspaceScope(os.tmpdir(), new NodeFileSystem());

    await expect(
      engine.extractFunction(path.join(os.tmpdir(), "some.vue"), 1, 1, 1, 10, "fn", scope),
    ).rejects.toMatchObject({ code: "NOT_SUPPORTED" });
  });
});

