import { execSync } from "node:child_process";
import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { walkFiles, walkWorkspaceFiles } from "./file-walk.js";

describe("walkFiles", () => {
  let tmpDir: string;

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "file-walk-test-"));
  });

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  function write(relPath: string, content = ""): string {
    const full = path.join(tmpDir, relPath);
    fs.mkdirSync(path.dirname(full), { recursive: true });
    fs.writeFileSync(full, content, "utf8");
    return full;
  }

  // ── non-git fallback ──────────────────────────────────────────────────────

  describe("non-git fallback (no .git dir)", () => {
    it("returns empty array when the directory does not exist", () => {
      // Exercises the walkRecursive try/catch path: readdirSync fails → []
      const nonExistent = path.join(tmpDir, "does-not-exist");
      const result = walkFiles(nonExistent, [".ts"]);
      expect(result).toEqual([]);
    });

    it("returns files matching extensions", () => {
      write("a.ts");
      write("b.tsx");
      write("c.vue");
      write("d.js"); // not requested

      const result = walkFiles(tmpDir, [".ts", ".tsx"]);
      const names = result.map((f) => path.basename(f)).sort();
      expect(names).toEqual(["a.ts", "b.tsx"]);
    });

    it("recurses into subdirectories", () => {
      write("src/a.ts");
      write("lib/b.ts");

      const result = walkFiles(tmpDir, [".ts"]);
      expect(result).toHaveLength(2);
    });

    it.each([
      ["node_modules", "node_modules/dep/index.ts"],
      ["dist", "dist/bundle.ts"],
      [".git", ".git/objects/a.ts"],
      [".nuxt", ".nuxt/a.ts"],
      [".output", ".output/a.ts"],
      [".vite", ".vite/a.ts"],
    ])("skips %s", (_dir, skippedFile) => {
      write("src/a.ts");
      write(skippedFile);
      expect(walkFiles(tmpDir, [".ts"])).toHaveLength(1);
    });

    it("returns .vue files when requested", () => {
      write("src/Comp.vue");
      write("src/utils.ts");

      const result = walkFiles(tmpDir, [".vue"]);
      expect(result).toHaveLength(1);
      expect(path.basename(result[0])).toBe("Comp.vue");
    });

    it("returns empty array when no matching files", () => {
      write("a.js");
      expect(walkFiles(tmpDir, [".ts"])).toEqual([]);
    });

    it("returns absolute paths", () => {
      write("src/a.ts");
      const result = walkFiles(tmpDir, [".ts"]);
      expect(path.isAbsolute(result[0])).toBe(true);
    });
  });

  // ── git repo ──────────────────────────────────────────────────────────────

  describe("git repo", () => {
    const gitEnv = { ...process.env, GIT_CONFIG_NOSYSTEM: "1" };

    function initGit() {
      execSync("git init", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
      execSync("git config user.email test@test.com", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
      execSync("git config user.name Test", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
    }

    it("returns staged .ts files", () => {
      initGit();
      write("src/a.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkFiles(tmpDir, [".ts"]);
      expect(result.map((f) => path.basename(f))).toContain("a.ts");
    });

    it("includes untracked files that are not gitignored", () => {
      initGit();
      write("src/a.ts");
      write("src/b.ts");
      execSync("git add src/a.ts", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
      // b.ts is untracked but not ignored — should still appear

      const result = walkFiles(tmpDir, [".ts"]);
      const names = result.map((f) => path.basename(f)).sort();
      expect(names).toContain("a.ts");
      expect(names).toContain("b.ts");
    });

    it("excludes gitignored files", () => {
      initGit();
      write(".gitignore", "dist/\n");
      write("src/a.ts");
      write("dist/b.ts"); // gitignored
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkFiles(tmpDir, [".ts"]);
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("b.ts");
    });

    it("returns absolute paths", () => {
      initGit();
      write("src/a.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkFiles(tmpDir, [".ts"]);
      expect(result.length).toBeGreaterThan(0);
      expect(path.isAbsolute(result[0])).toBe(true);
    });

    it("excludes gitignored files in directories not in SKIP_DIRS", () => {
      // "private/" is not in SKIP_DIRS, so the recursive fallback would include it.
      // This test ensures git mode (not the fallback) runs and respects .gitignore.
      initGit();
      write(".gitignore", "private/\n");
      write("src/a.ts");
      write("private/secret.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkFiles(tmpDir, [".ts"]);
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("secret.ts");
    });

    it("excludes files with non-matching extensions in git mode", () => {
      // Exercises the extension filter in the git path:
      // extSet.has(path.extname(line)) must exclude non-requested extensions.
      initGit();
      write("src/a.ts");
      write("src/b.vue"); // added to git but not requested
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkFiles(tmpDir, [".ts"]);
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("b.vue");
      expect(result).toHaveLength(1);
    });

    it("excludes git-tracked files deleted from disk", () => {
      // git ls-files --cached returns files that are tracked even if deleted.
      // walkFiles must filter these out to avoid ENOENT when callers read them.
      initGit();
      write("src/a.ts");
      write("src/b.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
      execSync('git commit -m "init"', { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      // Delete b.ts from disk but don't stage the deletion
      fs.unlinkSync(path.join(tmpDir, "src/b.ts"));

      const result = walkFiles(tmpDir, [".ts"]);
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("b.ts");
    });
  });
});

describe("walkWorkspaceFiles", () => {
  let tmpDir: string;

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "walk-workspace-test-"));
  });

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  function write(relPath: string, content = ""): string {
    const full = path.join(tmpDir, relPath);
    fs.mkdirSync(path.dirname(full), { recursive: true });
    fs.writeFileSync(full, content, "utf8");
    return full;
  }

  // ── non-git fallback ──────────────────────────────────────────────────────

  describe("non-git fallback (no .git dir)", () => {
    it("returns all files when no glob is given", () => {
      write("src/a.ts");
      write("src/b.js");
      write("README.md");

      const result = walkWorkspaceFiles(tmpDir);
      const names = result.map((f) => path.basename(f)).sort();
      expect(names).toEqual(["README.md", "a.ts", "b.js"]);
    });

    it("returns empty array when directory does not exist", () => {
      const nonExistent = path.join(tmpDir, "does-not-exist");
      expect(walkWorkspaceFiles(nonExistent)).toEqual([]);
    });

    it("filters by glob pattern", () => {
      write("src/a.ts");
      write("src/b.js");
      write("src/c.vue");

      const result = walkWorkspaceFiles(tmpDir, "**/*.ts");
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("b.js");
      expect(names).not.toContain("c.vue");
    });

    it("skips SKIP_DIRS", () => {
      write("src/a.ts");
      write("node_modules/dep/index.ts");
      write("dist/bundle.ts");

      const result = walkWorkspaceFiles(tmpDir);
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("index.ts");
      expect(names).not.toContain("bundle.ts");
    });

    it("returns absolute paths", () => {
      write("src/a.ts");
      const result = walkWorkspaceFiles(tmpDir);
      expect(result.length).toBeGreaterThan(0);
      expect(path.isAbsolute(result[0])).toBe(true);
    });

    it("glob matching a basename pattern matches across all directories", () => {
      write("src/main.ts");
      write("lib/main.ts");
      write("src/utils.ts");

      const result = walkWorkspaceFiles(tmpDir, "main.ts");
      const names = result.map((f) => path.basename(f));
      expect(names.every((n) => n === "main.ts")).toBe(true);
      expect(result).toHaveLength(2);
    });
  });

  // ── git repo ──────────────────────────────────────────────────────────────

  describe("git repo", () => {
    const gitEnv = { ...process.env, GIT_CONFIG_NOSYSTEM: "1" };

    function initGit() {
      execSync("git init", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
      execSync("git config user.email test@test.com", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
      execSync("git config user.name Test", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
    }

    it("returns all tracked and untracked files without a glob", () => {
      initGit();
      write("src/a.ts");
      write("src/b.js");
      execSync("git add src/a.ts", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });
      // b.js is untracked

      const result = walkWorkspaceFiles(tmpDir);
      const names = result.map((f) => path.basename(f)).sort();
      expect(names).toContain("a.ts");
      expect(names).toContain("b.js");
    });

    it("excludes gitignored files", () => {
      initGit();
      write(".gitignore", "dist/\n");
      write("src/a.ts");
      write("dist/bundle.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkWorkspaceFiles(tmpDir);
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("bundle.ts");
    });

    it("filters by glob in git mode", () => {
      initGit();
      write("src/a.ts");
      write("src/b.js");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkWorkspaceFiles(tmpDir, "**/*.ts");
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("b.js");
    });

    it("excludes gitignored files in directories not in SKIP_DIRS", () => {
      // "private/" is not in SKIP_DIRS so the fallback would include it,
      // but git mode must honor .gitignore and exclude it.
      initGit();
      write(".gitignore", "private/\n");
      write("src/a.ts");
      write("private/secret.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkWorkspaceFiles(tmpDir);
      const names = result.map((f) => path.basename(f));
      expect(names).toContain("a.ts");
      expect(names).not.toContain("secret.ts");
    });

    it("all returned paths exist on disk (empty git output lines are filtered)", () => {
      // git ls-files output ends with a newline, producing an empty last element.
      // Removing filter(Boolean) would cause path.join(workspace, '') = workspace dir itself.
      initGit();
      write("src/a.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkWorkspaceFiles(tmpDir);
      for (const f of result) {
        expect(fs.statSync(f).isFile()).toBe(true);
      }
      // Exactly 1 file, not a spurious workspace-root entry
      expect(result).toHaveLength(1);
    });

    it("does not include directories in the file list", () => {
      // Verifies walkRecursive only pushes files, not directories.
      initGit();
      write("src/a.ts");
      execSync("git add .", { cwd: tmpDir, env: gitEnv, stdio: "pipe" });

      const result = walkWorkspaceFiles(tmpDir);
      for (const f of result) {
        expect(fs.statSync(f).isFile()).toBe(true);
      }
    });
  });

  describe("non-git fallback directory check", () => {
    let tmpDir2: string;

    beforeEach(() => {
      tmpDir2 = fs.mkdtempSync(path.join(os.tmpdir(), "walk-workspace-nofile-"));
    });

    afterEach(() => {
      fs.rmSync(tmpDir2, { recursive: true, force: true });
    });

    it("does not include directories in the file list from recursive walk", () => {
      // Verifies the else-if (entry.isFile()) guard: directories must not be in output.
      const srcDir = path.join(tmpDir2, "src");
      fs.mkdirSync(srcDir, { recursive: true });
      fs.writeFileSync(path.join(srcDir, "a.ts"), "");

      const result = walkWorkspaceFiles(tmpDir2);
      for (const f of result) {
        expect(fs.statSync(f).isFile()).toBe(true);
      }
      expect(result.map((f) => path.basename(f))).toContain("a.ts");
    });
  });
});

src/ts-engine/move-symbol-imports.test.t.source:
/**
 * Tests for tsMoveSymbol — import rewriting orchestration.
 *
 * Covered here: orchestration (which files get scanned as importers, scope
 * tracking across multiple files). Rewrite edge cases (partial move, merge,
 * no-op when symbol not imported) are covered by ImportRewriter unit tests.
 */
import * as fs from "node:fs";
import * as path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import { cleanup, copyFixture, FIXTURES } from "../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { TsMorphEngine } from "./engine.js";
import { tsMoveSymbol } from "./move-symbol.js";

function makeScope(root: string): WorkspaceScope {
  return new WorkspaceScope(root, new NodeFileSystem());
}

function setupMultiImporter(): { dir: string; tsCompiler: TsMorphEngine; scope: WorkspaceScope } {
  const dir = copyFixture(FIXTURES.multiImporter.name);
  return { dir, tsCompiler: new TsMorphEngine(), scope: makeScope(dir) };
}

describe("tsMoveSymbol — import rewriting", () => {
  const dirs: string[] = [];
  afterEach(() => dirs.splice(0).forEach(cleanup));

  it("updates all importers when multiple files import the moved symbol", async () => {
    const { dir, tsCompiler, scope } = setupMultiImporter();
    dirs.push(dir);

    await tsMoveSymbol(
      tsCompiler,
      path.join(dir, "src/utils.ts"),
      "add",
      path.join(dir, "src/helpers.ts"),
      scope,
    );

    const featureA = fs.readFileSync(path.join(dir, "src/featureA.ts"), "utf8");
    const featureB = fs.readFileSync(path.join(dir, "src/featureB.ts"), "utf8");
    expect(featureA).toContain('"./helpers.js"');
    expect(featureB).toContain('"./helpers.js"');
    expect(scope.modified).toContain(path.join(dir, "src/featureA.ts"));
    expect(scope.modified).toContain(path.join(dir, "src/featureB.ts"));
  });
});

src/plugins/vue/plugin.test.ts.source:
import * as path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { cleanup, copyFixture, FIXTURES } from "../../__testHelpers__/helpers.js";
import {
  clearLanguagePlugins,
  invalidateAll,
  invalidateFile,
  makeRegistry,
  registerLanguagePlugin,
} from "../../daemon/language-plugin-registry.js";
import { TsMorphEngine } from "../../ts-engine/engine.js";
import { createVueLanguagePlugin } from "./plugin.js";

describe("Vue LanguagePlugin integration", () => {
  const dirs: string[] = [];

  beforeEach(() => {
    clearLanguagePlugins();
    registerLanguagePlugin(createVueLanguagePlugin());
  });

  afterEach(() => dirs.splice(0).forEach(cleanup));

  it("projectEngine returns VolarEngine for a Vue project", async () => {
    const dir = copyFixture(FIXTURES.vueProject.name);
    dirs.push(dir);
    const { VolarEngine } = await import("./engine.js");

    const registry = makeRegistry(path.join(dir, "src/composables/useCounter.ts"));
    const compiler = await registry.projectEngine();
    expect(compiler).toBeInstanceOf(VolarEngine);
  }, 10_000);

  it("projectEngine returns TsMorphEngine for a non-Vue project", async () => {
    const dir = copyFixture(FIXTURES.simpleTs.name);
    dirs.push(dir);

    const registry = makeRegistry(path.join(dir, "src/utils.ts"));
    const compiler = await registry.projectEngine();
    expect(compiler).toBeInstanceOf(TsMorphEngine);
  }, 10_000);

  it("invalidateFile before compiler is created does not throw", () => {
    expect(() => invalidateFile("/any/file.vue")).not.toThrow();
  });

  it("invalidateAll before compiler is created does not throw", () => {
    expect(() => invalidateAll()).not.toThrow();
  });

  it("invalidateAll clears cached engine so next createEngine call rebuilds it", async () => {
    const dir = copyFixture(FIXTURES.vueProject.name);
    dirs.push(dir);
    const { VolarEngine } = await import("./engine.js");

    const registry = makeRegistry(path.join(dir, "src/composables/useCounter.ts"));
    const first = await registry.projectEngine();
    invalidateAll();
    const second = await registry.projectEngine();

    expect(first).toBeInstanceOf(VolarEngine);
    expect(second).toBeInstanceOf(VolarEngine);
    expect(first).not.toBe(second);
  }, 15_000);
});

