import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { cleanup, copyFixture, FIXTURES } from "../../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../../domain/workspace-scope.js";
import { NodeFileSystem } from "../../ports/node-filesystem.js";
import {
  removeVueImportsOfDeletedFile,
  rewriteVueOwnImportsAfterMove,
  updateVueImportsAfterMove,
  updateVueImportsAfterSymbolMove,
} from "./scan.js";

// rewriteImports and computeRelativeSpecifier are private to their modules;
// tested here through the public updateVueImportsAfterMove API.

describe("updateVueImportsAfterMove", () => {
  let tmpDir: string;

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "scan-test-"));
  });

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  function writeVue(relPath: string, content: string): string {
    const full = path.join(tmpDir, relPath);
    fs.mkdirSync(path.dirname(full), { recursive: true });
    fs.writeFileSync(full, content, "utf8");
    return full;
  }

  function makeScope(dir: string): WorkspaceScope {
    return new WorkspaceScope(dir, new NodeFileSystem());
  }

  it("rewrites a same-directory import", () => {
    const oldPath = path.join(tmpDir, "src/utils.ts");
    const newPath = path.join(tmpDir, "src/helpers.ts");
    const vueFile = writeVue(
      "src/Comp.vue",
      `<script setup>\nimport foo from './utils'\n</script>`,
    );

    updateVueImportsAfterMove(oldPath, newPath, tmpDir, makeScope(tmpDir));

    const result = fs.readFileSync(vueFile, "utf8");
    expect(result).toContain("from './helpers.js'");
    expect(result).not.toContain("from './utils'");
  });

  it("rewrites a parent-directory import", () => {
    const oldPath = path.join(tmpDir, "shared/utils.ts");
    const newPath = path.join(tmpDir, "shared/helpers.ts");
    const vueFile = writeVue(
      "components/Comp.vue",
      `<script setup>\nimport foo from '../shared/utils'\n</script>`,
    );

    updateVueImportsAfterMove(oldPath, newPath, tmpDir, makeScope(tmpDir));

    const result = fs.readFileSync(vueFile, "utf8");
    expect(result).toContain("from '../shared/helpers.js'");
    expect(result).not.toContain("from '../shared/utils'");
  });

  it("does not rewrite imports that do not match the moved file", () => {
    const oldPath = path.join(tmpDir, "src/target.ts");
    const newPath = path.join(tmpDir, "src/renamed.ts");
    const original = `<script setup>\nimport foo from './other'\n</script>`;
    const vueFile = writeVue("src/Comp.vue", original);

    updateVueImportsAfterMove(oldPath, newPath, tmpDir, makeScope(tmpDir));

    expect(fs.readFileSync(vueFile, "utf8")).toBe(original);
  });

  it("records modified files in scope.modified", () => {
    const oldPath = path.join(tmpDir, "utils.ts");
    const newPath = path.join(tmpDir, "helpers.ts");
    writeVue("A.vue", `<script>\nimport x from './utils'\n</script>`);
    writeVue("B.vue", `<script>\nimport x from './other'\n</script>`);

    const scope = makeScope(tmpDir);
    updateVueImportsAfterMove(oldPath, newPath, tmpDir, scope);

    expect(scope.modified).toHaveLength(1);
    expect(path.basename(scope.modified[0])).toBe("A.vue");
  });

  it("scope.modified is empty when no .vue files are present", () => {
    const oldPath = path.join(tmpDir, "utils.ts");
    const newPath = path.join(tmpDir, "helpers.ts");

    const scope = makeScope(tmpDir);
    updateVueImportsAfterMove(oldPath, newPath, tmpDir, scope);

    expect(scope.modified).toEqual([]);
  });

  it("skips files outside workspace and does not write them", () => {
    const workspace = path.join(tmpDir, "src");
    fs.mkdirSync(workspace, { recursive: true });

    const oldPath = path.join(tmpDir, "src/utils.ts");
    const newPath = path.join(tmpDir, "src/helpers.ts");

    // This .vue file is outside the workspace (in other/, not src/)
    const outsideVue = writeVue(
      "other/Comp.vue",
      `<script setup>\nimport foo from '../src/utils'\n</script>`,
    );
    const originalContent = fs.readFileSync(outsideVue, "utf8");

    const scope = makeScope(workspace);
    updateVueImportsAfterMove(oldPath, newPath, tmpDir, scope);

    expect(scope.modified).toHaveLength(0);
    // File must not have been written
    expect(fs.readFileSync(outsideVue, "utf8")).toBe(originalContent);
  });

  it("handles double-quoted imports", () => {
    const oldPath = path.join(tmpDir, "src/utils.ts");
    const newPath = path.join(tmpDir, "src/helpers.ts");
    const vueFile = writeVue("src/Comp.vue", `<script>\nimport foo from "./utils"\n</script>`);

    updateVueImportsAfterMove(oldPath, newPath, tmpDir, makeScope(tmpDir));

    expect(fs.readFileSync(vueFile, "utf8")).toContain('from "./helpers.js"');
  });

  it("rewrites a deeply-nested import", () => {
    const oldPath = path.join(tmpDir, "lib/deep/util.ts");
    const newPath = path.join(tmpDir, "lib/deep/renamed.ts");
    const vueFile = writeVue(
      "views/Page.vue",
      `<script>\nimport x from '../lib/deep/util'\n</script>`,
    );

    updateVueImportsAfterMove(oldPath, newPath, tmpDir, makeScope(tmpDir));

    const result = fs.readFileSync(vueFile, "utf8");
    expect(result).toContain("from '../lib/deep/renamed.js'");
  });

  it("rewrites import with multiple spaces after from keyword", () => {
    const oldPath = path.join(tmpDir, "src/utils.ts");
    const newPath = path.join(tmpDir, "src/helpers.ts");
    const vueFile = writeVue(
      "src/Comp.vue",
      `<script setup>\nimport foo from  './utils'\n</script>`,
    );

    updateVueImportsAfterMove(oldPath, newPath, tmpDir, makeScope(tmpDir));

    // The replacement normalises whitespace to a single space.
    // The key assertion is that the rewrite DID happen (two-space import was matched).
    const result = fs.readFileSync(vueFile, "utf8");
    expect(result).toContain("from './helpers.js'");
    expect(result).not.toContain("'./utils'");
  });

  it("records unreadable .vue files as skipped", () => {
    const oldPath = path.join(tmpDir, "src/utils.ts");
    const newPath = path.join(tmpDir, "src/helpers.ts");
    const vueFile = writeVue(
      "src/Comp.vue",
      `<script setup>\nimport foo from './utils'\n</script>`,
    );
    fs.chmodSync(vueFile, 0o000);

    const scope = makeScope(tmpDir);
    updateVueImportsAfterMove(oldPath, newPath, tmpDir, scope);

    expect(scope.skipped).toContain(vueFile);
    expect(scope.modified).toHaveLength(0);

    fs.chmodSync(vueFile, 0o644);
  });
});

describe("updateVueImportsAfterSymbolMove", () => {
  const dirs: string[] = [];
  afterEach(() => dirs.splice(0).forEach(cleanup));

  function makeScope(dir: string): WorkspaceScope {
    return new WorkspaceScope(dir, new NodeFileSystem());
  }

  it("is a no-op when no matching .vue files exist", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "vue-noop-"));
    fs.mkdirSync(path.join(tmpDir, "src"), { recursive: true });
    fs.writeFileSync(path.join(tmpDir, "src/a.ts"), "export const foo = 1;\n");
    try {
      const scope = makeScope(tmpDir);
      updateVueImportsAfterSymbolMove(
        "foo",
        path.join(tmpDir, "src/a.ts"),
        path.join(tmpDir, "src/b.ts"),
        tmpDir,
        scope,
      );
      expect(scope.modified).toEqual([]);
      expect(scope.skipped).toEqual([]);
    } finally {
      fs.rmSync(tmpDir, { recursive: true, force: true });
    }
  });

  it("records nothing when no .vue files exist in the project", () => {
    const tsDir = copyFixture(FIXTURES.simpleTs.name);
    dirs.push(tsDir);
    const scope = makeScope(tsDir);
    updateVueImportsAfterSymbolMove(
      "greetUser",
      path.join(tsDir, "src/utils.ts"),
      path.join(tsDir, "src/helpers.ts"),
      tsDir,
      scope,
    );
    expect(scope.modified).toEqual([]);
    expect(scope.skipped).toEqual([]);
  });

  it("rewrites a matching named import in a .vue file", () => {
    const dir = copyFixture(FIXTURES.vueProject.name);
    dirs.push(dir);
    const scope = makeScope(dir);
    const sourceFile = path.join(dir, "src/composables/useCounter.ts");
    const destFile = path.join(dir, "src/composables/useTimer.ts");
    updateVueImportsAfterSymbolMove("useCounter", sourceFile, destFile, dir, scope);

    const appVue = path.join(dir, "src/App.vue");
    expect(scope.modified).toContain(appVue);
    const content = fs.readFileSync(appVue, "utf8");
    expect(content).toContain("useTimer");
    expect(content).not.toContain("useCounter.js");
    expect(content).not.toContain('from "./composables/useCounter"');
  });

  it("skips .vue files already in scope.modified", () => {
    const dir = copyFixture(FIXTURES.vueProject.name);
    dirs.push(dir);
    const scope = makeScope(dir);
    const appVue = path.join(dir, "src/App.vue");
    // Pre-mark App.vue as already modified
    scope.writeFile(appVue, fs.readFileSync(appVue, "utf8"));
    const contentBefore = fs.readFileSync(appVue, "utf8");

    const sourceFile = path.join(dir, "src/composables/useCounter.ts");
    const destFile = path.join(dir, "src/composables/useTimer.ts");
    updateVueImportsAfterSymbolMove("useCounter", sourceFile, destFile, dir, scope);

    // App.vue was already modified; Vue SFC scanning must skip it
    const contentAfter = fs.readFileSync(appVue, "utf8");
    expect(contentAfter).toBe(contentBefore);
  });

  it("does not modify .vue files that do not import the symbol", () => {
    const dir = copyFixture(FIXTURES.vueProject.name);
    dirs.push(dir);
    const scope = makeScope(dir);
    const sourceFile = path.join(dir, "src/composables/useCounter.ts");
    const destFile = path.join(dir, "src/composables/useTimer.ts");
    updateVueImportsAfterSymbolMove("nonExistentSymbol", sourceFile, destFile, dir, scope);

    expect(scope.modified).toEqual([]);
  });
});

describe("removeVueImportsOfDeletedFile", () => {
  let tmpDir: string;

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "scan-rm-test-"));
  });

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  function writeVue(relPath: string, content: string): string {
    const full = path.join(tmpDir, relPath);
    fs.mkdirSync(path.dirname(full), { recursive: true });
    fs.writeFileSync(full, content, "utf8");
    return full;
  }

  function makeScope(dir: string): WorkspaceScope {
    return new WorkspaceScope(dir, new NodeFileSystem());
  }

  it("records unreadable .vue files as skipped", () => {
    const deletedFile = path.join(tmpDir, "src/utils.ts");
    const vueFile = writeVue(
      "src/Comp.vue",
      `<script setup>\nimport foo from './utils'\n</script>`,
    );
    fs.chmodSync(vueFile, 0o000);

    const scope = makeScope(tmpDir);
    removeVueImportsOfDeletedFile(deletedFile, tmpDir, scope);

    expect(scope.skipped).toContain(vueFile);

    fs.chmodSync(vueFile, 0o644);
  });
});

describe("rewriteVueOwnImportsAfterMove", () => {
  let tmpDir: string;

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "scan-own-"));
  });

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  function write(relPath: string, content: string): string {
    const full = path.join(tmpDir, relPath);
    fs.mkdirSync(path.dirname(full), { recursive: true });
    fs.writeFileSync(full, content, "utf8");
    return full;
  }

  function makeScope(): WorkspaceScope {
    return new WorkspaceScope(tmpDir, new NodeFileSystem());
  }

  it("rewrites a relative import that no longer resolves from the new location", () => {
    write("src/utils/helper.ts", "");
    const content = `<script setup>\nimport { h } from '../utils/helper'\n</script>`;
    // File moved from src/components/Button.vue → src/ui/components/Button.vue
    const oldPath = path.join(tmpDir, "src/components/Button.vue");
    const newPath = path.join(tmpDir, "src/ui/components/Button.vue");
    write("src/ui/components/Button.vue", content);

    rewriteVueOwnImportsAfterMove(oldPath, newPath, makeScope());

    const result = fs.readFileSync(newPath, "utf8");
    expect(result).toContain("../../utils/helper");
    expect(result).not.toContain("'../utils/helper'");
  });

  it("does not rewrite an intra-directory import that still resolves from the new location", () => {
    // Both files moved together — relative import between them is still valid
    write("src/ui/components/Button.vue", "");
    const content = `<script setup>\nimport Icon from './Icon.vue'\n</script>`;
    write("src/ui/components/Card.vue", content);

    const oldPath = path.join(tmpDir, "src/components/Card.vue");
    const newPath = path.join(tmpDir, "src/ui/components/Card.vue");

    rewriteVueOwnImportsAfterMove(oldPath, newPath, makeScope());

    const result = fs.readFileSync(newPath, "utf8");
    expect(result).toContain("'./Icon.vue'");
  });

  it("does not rewrite an import that resolves from neither old nor new location", () => {
    const content = `<script setup>\nimport { x } from '../missing/module'\n</script>`;
    const oldPath = path.join(tmpDir, "src/components/Button.vue");
    const newPath = path.join(tmpDir, "src/ui/Button.vue");
    write("src/ui/Button.vue", content);

    rewriteVueOwnImportsAfterMove(oldPath, newPath, makeScope());

    const result = fs.readFileSync(newPath, "utf8");
    expect(result).toContain("'../missing/module'");
  });

  it("does nothing when the new file does not exist", () => {
    const oldPath = path.join(tmpDir, "src/components/Button.vue");
    const newPath = path.join(tmpDir, "src/ui/Button.vue");
    const scope = makeScope();

    // Should not throw
    rewriteVueOwnImportsAfterMove(oldPath, newPath, scope);
    expect(scope.modified).toHaveLength(0);
  });
});

src/ts-engine/import-rewriter.test.ts.source:
import { describe, expect, it } from "vitest";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { InMemoryFileSystem } from "../ports/in-memory-filesystem.js";
import { ImportRewriter } from "./import-rewriter.js";

const ROOT = "/project";

function makeScope(files: Record<string, string> = {}): WorkspaceScope {
  const vfs = new InMemoryFileSystem();
  for (const [path, content] of Object.entries(files)) {
    vfs.writeFile(path, content);
  }
  return new WorkspaceScope(ROOT, vfs);
}

function readFile(scope: WorkspaceScope, path: string): string {
  return scope.fs.readFile(path);
}

describe("ImportRewriter", () => {
  const rewriter = new ImportRewriter();

  describe("full-move: all named imports match", () => {
    it("repoints the module specifier to the new destination", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { MyFn } from "./utils.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/consumer.ts");
      expect(result).toContain(`from "./helpers.js"`);
      expect(result).not.toContain(`from "./utils.js"`);
    });

    it("records the file as modified", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { MyFn } from "./utils.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      expect(scope.modified).toContain("/project/src/consumer.ts");
    });

    it("handles bare specifier (no extension) pointing at source file", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { MyFn } from "./utils";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/consumer.ts");
      expect(result).toContain(`from "./helpers.js"`);
      expect(result).not.toContain(`"./utils"`);
    });

    it("handles .ts extension specifier", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { MyFn } from "./utils.ts";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/consumer.ts");
      expect(result).toContain(`from "./helpers.js"`);
      expect(result).not.toContain(`"./utils.ts"`);
    });
  });

  describe("partial-move: symbol is one of several imports", () => {
    it("removes symbol from old import and adds a new import from destination", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { MyFn, OtherFn } from "./utils.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/consumer.ts");
      // Old import keeps OtherFn but NOT MyFn
      expect(result).toMatch(/import\s*\{[^}]*OtherFn[^}]*\}\s*from\s*["']\.\/utils\.js["']/);
      expect(result).not.toMatch(/import\s*\{[^}]*MyFn[^}]*\}\s*from\s*["']\.\/utils\.js["']/);
      // New import has MyFn from helpers
      expect(result).toMatch(/import\s*\{[^}]*MyFn[^}]*\}\s*from\s*["']\.\/helpers\.js["']/);
    });

    it("does not lose the remaining symbol after the split", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { A, B, C } from "./utils.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "B",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/consumer.ts");
      expect(result).toContain("A");
      expect(result).toContain("C");
      expect(result).toContain(`from "./helpers.js"`);
    });
  });

  describe("merge with existing destination import", () => {
    it("merges a full-move into an existing import — single import declaration for dest", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { MyFn } from "./utils.js";\nimport { ExistingFn } from "./helpers.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/consumer.ts");
      // Both symbols appear in a single import from helpers
      expect(result).toContain("MyFn");
      expect(result).toContain("ExistingFn");
      // The old utils import is removed entirely
      expect(result).not.toContain(`from "./utils.js"`);
      // Only one import declaration for helpers (merged, not duplicated)
      const helperImports = result.match(/from ["']\.\/helpers\.js["']/g);
      expect(helperImports).toHaveLength(1);
    });

    it("merges a partial-move into an existing import from the destination", () => {
      const scope = makeScope({
        "/project/src/consumer.ts": `import { MyFn, OtherFn } from "./utils.js";\nimport { ExistingFn } from "./helpers.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/consumer.ts");
      // MyFn merged into existing helpers import
      expect(result).toContain("MyFn");
      expect(result).toContain("ExistingFn");
      // OtherFn stays on the old utils import
      expect(result).toContain("OtherFn");
      expect(result).toContain(`from "./utils.js"`);
      // Only one import from helpers (merged, not a second declaration)
      const helperImports = result.match(/from ["']\.\/helpers\.js["']/g);
      expect(helperImports).toHaveLength(1);
    });
  });

  describe("export re-exports", () => {
    it("repoints a full re-export specifier to the new destination", () => {
      const scope = makeScope({
        "/project/src/barrel.ts": `export { MyFn } from "./utils.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/barrel.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/barrel.ts");
      expect(result).toContain(`from "./helpers.js"`);
      expect(result).not.toContain(`from "./utils.js"`);
    });

    it("splits a partial re-export into old and new export declarations", () => {
      const scope = makeScope({
        "/project/src/barrel.ts": `export { MyFn, OtherFn } from "./utils.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/barrel.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/barrel.ts");
      // Old export keeps OtherFn but NOT MyFn
      expect(result).toMatch(/export\s*\{[^}]*OtherFn[^}]*\}\s*from\s*["']\.\/utils\.js["']/);
      expect(result).not.toMatch(/export\s*\{[^}]*MyFn[^}]*\}\s*from\s*["']\.\/utils\.js["']/);
      // New export has MyFn from helpers
      expect(result).toMatch(/export\s*\{[^}]*MyFn[^}]*\}\s*from\s*["']\.\/helpers\.js["']/);
    });
  });

  describe("no-op cases", () => {
    it.each([
      ["symbol not imported at all", `import { SomethingElse } from "./utils.js";\n`],
      [
        "imports from old source but not the moved symbol",
        `import { OtherFn } from "./utils.js";\n`,
      ],
      ["bare export with no module specifier", `const MyFn = () => {};\nexport { MyFn };\n`],
      ["imports symbol from an unrelated module", `import { MyFn } from "./other.js";\n`],
    ])("does not modify file when %s", (_desc, original) => {
      const scope = makeScope({ "/project/src/consumer.ts": original });
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      expect(readFile(scope, "/project/src/consumer.ts")).toBe(original);
      expect(scope.modified).not.toContain("/project/src/consumer.ts");
    });

    it("handles an empty files iterable without error", () => {
      const scope = makeScope();
      expect(() =>
        rewriter.rewrite([], "MyFn", "/project/src/utils.ts", "/project/src/helpers.ts", scope),
      ).not.toThrow();
      expect(scope.modified).toHaveLength(0);
    });
  });

  describe("out-of-workspace files", () => {
    it("records a file outside the workspace as skipped without modifying it", () => {
      const scope = makeScope({
        "/external/consumer.ts": `import { MyFn } from "../project/src/utils.js";\n`,
      });
      rewriter.rewrite(
        ["/external/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      expect(scope.skipped).toContain("/external/consumer.ts");
      expect(scope.modified).not.toContain("/external/consumer.ts");
    });

    it("does not write to a file outside the workspace", () => {
      const original = `import { MyFn } from "../project/src/utils.js";\n`;
      const vfs = new InMemoryFileSystem();
      vfs.writeFile("/external/consumer.ts", original);
      const scope = new WorkspaceScope(ROOT, vfs);
      rewriter.rewrite(
        ["/external/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      expect(vfs.readFile("/external/consumer.ts")).toBe(original);
    });
  });

  describe("rewriteScript standalone", () => {
    it("rewrites script content without reading/writing files", () => {
      const content = `import { MyFn } from "./utils.js";\n`;
      const scope = makeScope();
      const result = rewriter.rewriteScript(
        "/project/src/component.ts",
        content,
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      expect(result).toContain(`from "./helpers.js"`);
      expect(result).not.toContain(`from "./utils.js"`);
    });

    it("returns null when no matching declarations found", () => {
      const content = `import { Other } from "./other.js";\n`;
      const scope = makeScope();
      const result = rewriter.rewriteScript(
        "/project/src/component.ts",
        content,
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      expect(result).toBeNull();
    });
  });

  describe("specifier extension matching", () => {
    it("skips a .js specifier that resolves to a real .js file on disk", () => {
      const original = `import { MyFn } from "./utils.js";\n`;
      const vfs = new InMemoryFileSystem();
      vfs.writeFile("/project/src/consumer.ts", original);
      vfs.writeFile("/project/src/utils.js", "// real js file");
      const scope = new WorkspaceScope(ROOT, vfs);
      rewriter.rewrite(
        ["/project/src/consumer.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      expect(readFile(scope, "/project/src/consumer.ts")).toBe(original);
      expect(scope.modified).not.toContain("/project/src/consumer.ts");
    });
  });

  describe("cross-directory imports", () => {
    it("computes correct specifiers for files in different directories", () => {
      const scope = makeScope({
        "/project/src/features/feature.ts": `import { MyFn } from "../utils.js";\n`,
      });
      rewriter.rewrite(
        ["/project/src/features/feature.ts"],
        "MyFn",
        "/project/src/utils.ts",
        "/project/src/helpers.ts",
        scope,
      );
      const result = readFile(scope, "/project/src/features/feature.ts");
      expect(result).toContain(`from "../helpers.js"`);
      expect(result).not.toContain(`from "../utils.js"`);
    });
  });
});

src/operations/replaceText.test.ts.source:
import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { describe, expect } from "vitest";
import { cleanup, FIXTURES, readFile, fixtureTest as test } from "../__testHelpers__/helpers.js";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { replaceText } from "./replaceText.js";

function makeScope(dir: string): WorkspaceScope {
  return new WorkspaceScope(dir, new NodeFileSystem());
}

describe("replaceText operation", () => {
  // ─── Pattern mode ───────────────────────────────────────────────────────

  describe("pattern mode", () => {
    test.override({ fixtureName: FIXTURES.simpleTs.name });

    test("replaces all occurrences across workspace files", async ({ dir }) => {
      const before = readFile(dir, "src/utils.ts");
      expect(before).toContain("greetUser");

      const result = await replaceText(makeScope(dir), {
        pattern: "greetUser",
        replacement: "welcomeUser",
      });

      expect(result.replacementCount).toBeGreaterThanOrEqual(2);
      expect(result.filesModified.length).toBeGreaterThanOrEqual(2);

      const utilsAfter = readFile(dir, "src/utils.ts");
      expect(utilsAfter).toContain("welcomeUser");
      expect(utilsAfter).not.toContain("greetUser");

      const mainAfter = readFile(dir, "src/main.ts");
      expect(mainAfter).toContain("welcomeUser");
      expect(mainAfter).not.toContain("greetUser");
    });

    test("restricts replacement to files matching glob", async ({ dir }) => {
      const result = await replaceText(makeScope(dir), {
        pattern: "greetUser",
        replacement: "welcomeUser",
        glob: "**/utils.ts",
      });

      expect(result.filesModified).toHaveLength(1);
      expect(result.filesModified[0]).toContain("utils.ts");

      // main.ts should be untouched
      const mainAfter = readFile(dir, "src/main.ts");
      expect(mainAfter).toContain("greetUser");
    });

    test("supports regex capture groups in replacement", async ({ dir }) => {
      // Wrap "greetUser" in parens → "GREET(greetUser)"
      const result = await replaceText(makeScope(dir), {
        pattern: "(greetUser)",
        replacement: "GREET($1)",
        glob: "**/utils.ts",
      });

      expect(result.replacementCount).toBeGreaterThan(0);
      const after = readFile(dir, "src/utils.ts");
      expect(after).toContain("GREET(greetUser)");
    });

    test("records unreadable files as skipped", async ({ dir: _dir }) => {
      const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-replace-skip-"));
      try {
        fs.mkdirSync(path.join(dir, "src"), { recursive: true });
        fs.writeFileSync(path.join(dir, "src/ok.ts"), "export const foo = 'bar';\n");
        const unreadable = path.join(dir, "src/secret.ts");
        fs.writeFileSync(unreadable, "export const foo = 'secret';\n");
        fs.chmodSync(unreadable, 0o000);

        const scope = makeScope(dir);
        await replaceText(scope, { pattern: "foo", replacement: "baz" });

        expect(scope.skipped).toContain(unreadable);

        fs.chmodSync(unreadable, 0o644);
      } finally {
        cleanup(dir);
      }
    });

    test("returns empty result when no files match the pattern", async ({ dir: _dir }) => {
      const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-tmp-"));
      try {
        const result = await replaceText(makeScope(dir), {
          pattern: "zzz_not_present_zzz",
          replacement: "replaced",
        });

        expect(result.filesModified).toHaveLength(0);
        expect(result.replacementCount).toBe(0);
      } finally {
        cleanup(dir);
      }
    });

    test("throws PARSE_ERROR for invalid regex", async ({ dir: _dir }) => {
      const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-tmp-"));
      try {
        await expect(
          replaceText(makeScope(dir), { pattern: "[bad", replacement: "x" }),
        ).rejects.toMatchObject({
          code: "PARSE_ERROR",
        });
      } finally {
        cleanup(dir);
      }
    });

    test("throws REDOS for a catastrophic backtracking pattern", async ({ dir: _dir }) => {
      const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-tmp-"));
      try {
        await expect(
          replaceText(makeScope(dir), { pattern: "(a+)+$", replacement: "x" }),
        ).rejects.toMatchObject({ code: "REDOS" });
      } finally {
        cleanup(dir);
      }
    });

    test("does not modify sensitive files", async ({ dir }) => {
      const envPath = path.join(dir, ".env");
      fs.writeFileSync(envPath, "greetUser=secret\n");

      const result = await replaceText(makeScope(dir), {
        pattern: "greetUser",
        replacement: "welcomeUser",
      });

      // .env must not appear in filesModified
      expect(result.filesModified.every((f) => !f.endsWith(".env"))).toBe(true);
      // .env content must be unchanged
      expect(fs.readFileSync(envPath, "utf8")).toContain("greetUser");
    });

    test("rejects paths outside the workspace", async ({ dir: _dir }) => {
      const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-tmp-"));
      try {
        // edits array with a file outside workspace
        await expect(
          replaceText(makeScope(dir), {
            edits: [{ file: "/etc/passwd", line: 1, col: 1, oldText: "root", newText: "replaced" }],
          }),
        ).rejects.toMatchObject({ code: "WORKSPACE_VIOLATION" });
      } finally {
        cleanup(dir);
      }
    });
  });

  // ─── Surgical mode ──────────────────────────────────────────────────────

  describe("surgical mode", () => {
    test.override({ fixtureName: FIXTURES.simpleTs.name });

    test("applies exact text edits at specified locations", async ({ dir }) => {
      // utils.ts line 1, col 17: "greetUser"
      const result = await replaceText(makeScope(dir), {
        edits: [
          {
            file: path.join(dir, "src/utils.ts"),
            line: 1,
            col: 17,
            oldText: "greetUser",
            newText: "welcomeUser",
          },
        ],
      });

      expect(result.filesModified).toHaveLength(1);
      expect(result.replacementCount).toBe(1);

      const after = readFile(dir, "src/utils.ts");
      expect(after).toContain("welcomeUser");
    });

    test("throws TEXT_MISMATCH when oldText does not match", async ({ dir }) => {
      await expect(
        replaceText(makeScope(dir), {
          edits: [
            {
              file: path.join(dir, "src/utils.ts"),
              line: 1,
              col: 17,
              oldText: "wrongName",
              newText: "whatever",
            },
          ],
        }),
      ).rejects.toMatchObject({ code: "TEXT_MISMATCH" });
    });

    test("applies multiple edits to the same file correctly", async ({ dir }) => {
      // utils.ts line 1: "export function greetUser(name: string): string {"
      // "greetUser" at col 17, "name" at col 27, "string" at col 33
      const result = await replaceText(makeScope(dir), {
        edits: [
          {
            file: path.join(dir, "src/utils.ts"),
            line: 1,
            col: 17,
            oldText: "greetUser",
            newText: "hi",
          },
          {
            file: path.join(dir, "src/utils.ts"),
            line: 1,
            col: 27,
            oldText: "name",
            newText: "user",
          },
        ],
      });

      expect(result.replacementCount).toBe(2);
      const after = readFile(dir, "src/utils.ts");
      expect(after).toContain("hi");
      expect(after).toContain("user");
    });

    test("rejects edits to sensitive files", async ({ dir }) => {
      const envPath = path.join(dir, ".env");
      fs.writeFileSync(envPath, "KEY=value\n");

      await expect(
        replaceText(makeScope(dir), {
          edits: [{ file: envPath, line: 1, col: 1, oldText: "KEY", newText: "SECRET" }],
        }),
      ).rejects.toMatchObject({ code: "SENSITIVE_FILE" });
    });

    test("throws WORKSPACE_VIOLATION for edits outside workspace", async ({ dir }) => {
      await expect(
        replaceText(makeScope(dir), {
          edits: [{ file: "/etc/passwd", line: 1, col: 1, oldText: "root", newText: "x" }],
        }),
      ).rejects.toMatchObject({ code: "WORKSPACE_VIOLATION" });
    });

    test("requires either pattern+replacement or edits", async ({ dir: _dir }) => {
      const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-tmp-"));
      try {
        await expect(replaceText(makeScope(dir), {})).rejects.toMatchObject({
          code: "VALIDATION_ERROR",
        });
      } finally {
        cleanup(dir);
      }
    });
  });
});

