import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { isDaemonAlive, removeDaemonFiles } from "./daemon";
import { lockfilePath, socketPath } from "./paths";

const WORKSPACE_A = "/tmp/test-workspace-alpha";
const WORKSPACE_B = "/tmp/test-workspace-beta";
const CACHE_DIR = path.join(os.homedir(), ".cache", "weaver");

describe("socketPath / lockfilePath", () => {
  it("returns a .sock path inside the cache dir", () => {
    const p = socketPath(WORKSPACE_A);
    expect(p).toMatch(/\.sock$/);
    expect(p.startsWith(CACHE_DIR)).toBe(true);
  });

  it("returns a .pid path inside the cache dir", () => {
    const p = lockfilePath(WORKSPACE_A);
    expect(p).toMatch(/\.pid$/);
    expect(p.startsWith(CACHE_DIR)).toBe(true);
  });

  it("is deterministic — same workspace → same path", () => {
    expect(socketPath(WORKSPACE_A)).toBe(socketPath(WORKSPACE_A));
    expect(lockfilePath(WORKSPACE_A)).toBe(lockfilePath(WORKSPACE_A));
  });

  it("different workspaces → different paths", () => {
    expect(socketPath(WORKSPACE_A)).not.toBe(socketPath(WORKSPACE_B));
    expect(lockfilePath(WORKSPACE_A)).not.toBe(lockfilePath(WORKSPACE_B));
  });

  it("socket and lockfile paths are different for the same workspace", () => {
    expect(socketPath(WORKSPACE_A)).not.toBe(lockfilePath(WORKSPACE_A));
  });
});

describe("isDaemonAlive", () => {
  const testWorkspace = "/tmp/test-daemon-alive-workspace";

  beforeEach(() => {
    fs.mkdirSync(CACHE_DIR, { recursive: true });
    // Clean up any leftover files
    removeDaemonFiles(testWorkspace);
  });

  afterEach(() => {
    removeDaemonFiles(testWorkspace);
  });

  it("returns false when no lockfile exists", () => {
    expect(isDaemonAlive(testWorkspace)).toBe(false);
  });

  it("returns false when lockfile is malformed (not JSON)", () => {
    fs.writeFileSync(lockfilePath(testWorkspace), "not-a-pid");
    expect(isDaemonAlive(testWorkspace)).toBe(false);
  });

  it("returns false when lockfile contains a non-existent PID", () => {
    // PID 999999999 is extremely unlikely to exist
    fs.writeFileSync(
      lockfilePath(testWorkspace),
      JSON.stringify({ pid: 999999999, startedAt: Date.now() }),
    );
    expect(isDaemonAlive(testWorkspace)).toBe(false);
  });

  it("returns true when lockfile has a live PID and socket file exists", () => {
    fs.mkdirSync(path.dirname(socketPath(testWorkspace)), { recursive: true });
    fs.writeFileSync(socketPath(testWorkspace), "");
    fs.writeFileSync(
      lockfilePath(testWorkspace),
      JSON.stringify({ pid: process.pid, startedAt: Date.now() }),
    );
    expect(isDaemonAlive(testWorkspace)).toBe(true);
  });

  it("returns false when lockfile has a live PID but socket file is missing", () => {
    fs.writeFileSync(
      lockfilePath(testWorkspace),
      JSON.stringify({ pid: process.pid, startedAt: Date.now() }),
    );
    expect(isDaemonAlive(testWorkspace)).toBe(false);
  });
});

describe("removeDaemonFiles", () => {
  const testWorkspace = "/tmp/test-daemon-remove-workspace";

  beforeEach(() => {
    fs.mkdirSync(CACHE_DIR, { recursive: true });
  });

  afterEach(() => {
    removeDaemonFiles(testWorkspace);
  });

  it("removes socket and lockfile when they exist", () => {
    fs.writeFileSync(socketPath(testWorkspace), "");
    fs.writeFileSync(lockfilePath(testWorkspace), "");
    removeDaemonFiles(testWorkspace);
    expect(fs.existsSync(socketPath(testWorkspace))).toBe(false);
    expect(fs.existsSync(lockfilePath(testWorkspace))).toBe(false);
  });

  it("does not throw when files do not exist", () => {
    expect(() => removeDaemonFiles(testWorkspace)).not.toThrow();
  });
});

src/operations/moveSymbol.test.ts.source:
import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { WorkspaceScope } from "../domain/workspace-scope.js";
import { NodeFileSystem } from "../ports/node-filesystem.js";
import { makeMockCompiler } from "../ts-engine/__testHelpers__/mock-compiler.js";
import { moveSymbol } from "./moveSymbol.js";

/**
 * Create a temporary directory with a real source file so assertFileExists passes.
 * Returns the dir, source path, dest path, and a scope rooted at the dir.
 */
function makeRealScope() {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), "ns-movesymbol-unit-"));
  fs.mkdirSync(path.join(dir, "src"), { recursive: true });
  const source = path.join(dir, "src/utils.ts");
  const dest = path.join(dir, "src/helpers.ts");
  fs.writeFileSync(source, "export function greetUser(name: string): string { return name; }\n");
  const scope = new WorkspaceScope(dir, new NodeFileSystem());
  return { dir, source, dest, scope };
}

const SYMBOL = "greetUser";

describe("moveSymbol operation (thin orchestrator)", () => {
  const dirs: string[] = [];
  let dir: string;
  let source: string;
  let dest: string;
  let scope: WorkspaceScope;

  beforeEach(() => {
    ({ dir, source, dest, scope } = makeRealScope());
    dirs.push(dir);
  });

  afterEach(() => {
    for (const d of dirs.splice(0)) {
      fs.rmSync(d, { recursive: true, force: true });
    }
  });

  describe("orchestrator delegates to engine", () => {
    it("calls engine.moveSymbol with resolved absolute paths, symbol, scope, and options", async () => {
      const engine = makeMockCompiler();

      await moveSymbol(engine, source, SYMBOL, dest, scope);

      expect(engine.moveSymbol).toHaveBeenCalledWith(
        path.resolve(source),
        SYMBOL,
        path.resolve(dest),
        scope,
        undefined,
      );
    });

    it("forwards options to engine.moveSymbol", async () => {
      const engine = makeMockCompiler();
      const opts = { force: true };

      await moveSymbol(engine, source, SYMBOL, dest, scope, opts);

      expect(engine.moveSymbol).toHaveBeenCalledWith(
        path.resolve(source),
        SYMBOL,
        path.resolve(dest),
        scope,
        opts,
      );
    });
  });

  describe("scope modifications flow to result", () => {
    it("files recorded into scope by engine.moveSymbol appear in filesModified", async () => {
      const extraFile = path.join(dir, "src/extra.ts");
      const engine = makeMockCompiler({
        moveSymbol: vi
          .fn()
          .mockImplementation((_src: string, _sym: string, _dst: string, s: WorkspaceScope) => {
            s.recordModified(extraFile);
          }),
      });

      const result = await moveSymbol(engine, source, SYMBOL, dest, scope);

      expect(result.filesModified).toContain(extraFile);
    });

    it("skipped files recorded into scope by engine.moveSymbol appear in filesSkipped", async () => {
      const skippedFile = "/outside/workspace/file.vue";
      const engine = makeMockCompiler({
        moveSymbol: vi
          .fn()
          .mockImplementation((_src: string, _sym: string, _dst: string, s: WorkspaceScope) => {
            s.recordSkipped(skippedFile);
          }),
      });

      const result = await moveSymbol(engine, source, SYMBOL, dest, scope);

      expect(result.filesSkipped).toContain(skippedFile);
    });
  });

  describe("return shape", () => {
    it("returns correct filesModified, filesSkipped, symbolName, sourceFile, and destFile", async () => {
      const capturedSource = source;
      const capturedDest = dest;
      const engine = makeMockCompiler({
        moveSymbol: vi
          .fn()
          .mockImplementation((_src: string, _sym: string, _dst: string, s: WorkspaceScope) => {
            s.recordModified(capturedSource);
            s.recordModified(capturedDest);
          }),
      });

      const result = await moveSymbol(engine, source, SYMBOL, dest, scope);

      expect(result.symbolName).toBe(SYMBOL);
      expect(result.sourceFile).toBe(path.resolve(source));
      expect(result.destFile).toBe(path.resolve(dest));
      expect(result.filesModified).toContain(source);
      expect(result.filesModified).toContain(dest);
      expect(result.filesSkipped).toEqual([]);
    });
  });

  describe("assertFileExists", () => {
    it("throws FILE_NOT_FOUND when the source file does not exist", async () => {
      const engine = makeMockCompiler();
      const missingSource = path.join(dir, "src/doesNotExist.ts");

      await expect(moveSymbol(engine, missingSource, SYMBOL, dest, scope)).rejects.toMatchObject({
        code: "FILE_NOT_FOUND",
      });
    });
  });
});

