src/utils/assert-file.test.ts.source:
import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import { EngineError } from "../domain/errors.js";
import { assertFileExists } from "./assert-file.js";

describe("assertFileExists", () => {
  const tmpDirs: string[] = [];
  afterEach(() => {
    for (const d of tmpDirs.splice(0)) {
      fs.rmSync(d, { recursive: true, force: true });
    }
  });

  it("returns the resolved absolute path for an existing file", () => {
    const dir = fs.mkdtempSync(path.join(os.tmpdir(), "assert-file-"));
    tmpDirs.push(dir);
    const filePath = path.join(dir, "test.ts");
    fs.writeFileSync(filePath, "");

    const result = assertFileExists(filePath);
    expect(result).toBe(path.resolve(filePath));
  });

  it("resolves relative paths to absolute", () => {
    const dir = fs.mkdtempSync(path.join(os.tmpdir(), "assert-file-"));
    tmpDirs.push(dir);
    const filePath = path.join(dir, "test.ts");
    fs.writeFileSync(filePath, "");

    // Temporarily change cwd won't work reliably; use absolute path directly.
    const result = assertFileExists(filePath);
    expect(path.isAbsolute(result)).toBe(true);
  });

  it("throws FILE_NOT_FOUND for a missing file", () => {
    expect(() => assertFileExists("/nonexistent/path/file.ts")).toThrow(EngineError);
    expect(() => assertFileExists("/nonexistent/path/file.ts")).toThrow(
      expect.objectContaining({ code: "FILE_NOT_FOUND" }),
    );
  });

  it("includes the original filePath in the error message", () => {
    const missing = "/no/such/file.ts";
    let err: unknown;
    try {
      assertFileExists(missing);
    } catch (e) {
      err = e;
    }
    expect(err).toBeInstanceOf(EngineError);
    expect((err as EngineError).message).toContain(missing);
  });
});

src/utils/relative-path.test.ts.source:
import { describe, expect, it } from "vitest";
import { computeRelativeImportPath } from "./relative-path.js";

describe("computeRelativeImportPath", () => {
  describe("TypeScript source extensions → .js runtime extension", () => {
    it.each([
      { src: "b.ts", expected: "./b.js", desc: ".ts → .js" },
      { src: "comp.tsx", expected: "./comp.js", desc: ".tsx → .js" },
      { src: "comp.jsx", expected: "./comp.js", desc: ".jsx → .js" },
      { src: "worker.mts", expected: "./worker.mjs", desc: ".mts → .mjs" },
      { src: "legacy.cts", expected: "./legacy.cjs", desc: ".cts → .cjs" },
    ])("$desc", ({ src, expected }) => {
      expect(computeRelativeImportPath("/project/src/a.ts", `/project/src/${src}`)).toBe(expected);
    });
  });

  describe("JavaScript runtime extensions → unchanged", () => {
    it.each([
      { src: "utils.js", expected: "./utils.js", desc: ".js kept" },
      { src: "worker.mjs", expected: "./worker.mjs", desc: ".mjs kept" },
      { src: "legacy.cjs", expected: "./legacy.cjs", desc: ".cjs kept" },
    ])("$desc", ({ src, expected }) => {
      expect(computeRelativeImportPath("/project/src/a.ts", `/project/src/${src}`)).toBe(expected);
    });
  });

  describe("non-TS extensions → left untouched", () => {
    it.each([
      { src: "App.vue", expected: "./App.vue", desc: ".vue unchanged" },
      { src: "data.json", expected: "./data.json", desc: ".json unchanged" },
    ])("$desc", ({ src, expected }) => {
      expect(computeRelativeImportPath("/project/src/a.ts", `/project/src/${src}`)).toBe(expected);
    });
  });

  describe("path shape", () => {
    it("parent-directory specifier", () => {
      expect(computeRelativeImportPath("/project/src/sub/a.ts", "/project/src/utils.ts")).toBe(
        "../utils.js",
      );
    });

    it("child-directory specifier", () => {
      expect(computeRelativeImportPath("/project/src/a.ts", "/project/src/utils/helpers.ts")).toBe(
        "./utils/helpers.js",
      );
    });

    it("always starts with ./ or ../", () => {
      const result = computeRelativeImportPath("/project/src/a.ts", "/project/src/b.ts");
      expect(result.startsWith(".")).toBe(true);
    });

    it("index file keeps the index filename (no directory collapse)", () => {
      expect(computeRelativeImportPath("/project/src/a.ts", "/project/src/utils/index.ts")).toBe(
        "./utils/index.js",
      );
    });
  });
});

src/adapters/mcp/classify-error.test.ts.source:
import { describe, expect, it } from "vitest";
import { classifyDaemonError } from "./classify-error.js";

describe("classifyDaemonError", () => {
  it("returns DAEMON_STARTING for ECONNREFUSED (daemon not yet listening)", () => {
    const err = Object.assign(new Error("connect ECONNREFUSED /tmp/sock"), {
      code: "ECONNREFUSED",
    });
    expect(classifyDaemonError(err)).toBe("DAEMON_STARTING");
  });

  it("returns DAEMON_STARTING for ENOENT (socket file missing)", () => {
    const err = Object.assign(new Error("no such file or directory"), { code: "ENOENT" });
    expect(classifyDaemonError(err)).toBe("DAEMON_STARTING");
  });

  it("returns DAEMON_STARTING for ECONNRESET (daemon crashed mid-response)", () => {
    const err = Object.assign(new Error("read ECONNRESET"), { code: "ECONNRESET" });
    expect(classifyDaemonError(err)).toBe("DAEMON_STARTING");
  });

  it("returns DAEMON_STARTING for timeout (daemon slow to respond)", () => {
    const err = new Error("callDaemon timed out after 30000ms");
    expect(classifyDaemonError(err)).toBe("DAEMON_STARTING");
  });

  it("returns INTERNAL_ERROR for JSON parse failures (malformed daemon response)", () => {
    const err = new SyntaxError("Unexpected token < in JSON at position 0");
    expect(classifyDaemonError(err)).toBe("INTERNAL_ERROR");
  });

  it("returns INTERNAL_ERROR for unexpected Error types", () => {
    expect(classifyDaemonError(new Error("something else went wrong"))).toBe("INTERNAL_ERROR");
  });

  it("returns INTERNAL_ERROR for non-Error values", () => {
    expect(classifyDaemonError("string error")).toBe("INTERNAL_ERROR");
    expect(classifyDaemonError(null)).toBe("INTERNAL_ERROR");
    expect(classifyDaemonError(42)).toBe("INTERNAL_ERROR");
  });
});

src/domain/errors.test.ts.source:
import { describe, expect, it } from "vitest";
import { EngineError } from "./errors.js";

describe("EngineError", () => {
  it("constructs with message and code", () => {
    const err = new EngineError("file missing", "FILE_NOT_FOUND");
    expect(err.message).toBe("file missing");
    expect(err.code).toBe("FILE_NOT_FOUND");
    expect(err.name).toBe("EngineError");
    expect(err instanceof Error).toBe(true);
    expect(err instanceof EngineError).toBe(true);
  });

  it("is() returns true for any EngineError when no code given", () => {
    const err = new EngineError("oops", "SYMBOL_NOT_FOUND");
    expect(EngineError.is(err)).toBe(true);
  });

  it("is() returns true for matching code", () => {
    const err = new EngineError("oops", "SYMBOL_NOT_FOUND");
    expect(EngineError.is(err, "SYMBOL_NOT_FOUND")).toBe(true);
  });

  it("is() returns false for wrong code", () => {
    const err = new EngineError("oops", "SYMBOL_NOT_FOUND");
    expect(EngineError.is(err, "FILE_NOT_FOUND")).toBe(false);
  });

  it("is() returns false for plain Error", () => {
    const err = new Error("plain");
    expect(EngineError.is(err)).toBe(false);
  });

  it("is() returns false for non-error values", () => {
    expect(EngineError.is(null)).toBe(false);
    expect(EngineError.is(undefined)).toBe(false);
    expect(EngineError.is("string")).toBe(false);
    expect(EngineError.is(42)).toBe(false);
  });
});
